#!/usr/bin/env bun
import { writed, file } from "bun";

const PROMPTS_URL = "https://raw.githubusercontent.com/f/prompts.chat/master/prompts.csv";
const OUTPUT_PATH = ".agent/skills/prompts-chat/prompts.csv";

async function fetchPrompts() {
    console.log(`Fetching prompts from ${PROMPTS_URL}...`);
    try {
        const response = await fetch(PROMPTS_URL);
        if (!response.ok) {
            throw new Error(`Failed to fetch prompts: ${response.statusText}`);
        }
        const csvContent = await response.text();
        await Bun.write(OUTPUT_PATH, csvContent);
        console.log(`Successfully saved prompts to ${OUTPUT_PATH}`);
    } catch (error) {
        console.error("Error fetching prompts:", error);
        process.exit(1);
    }
}

fetchPrompts();

import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest';
import { CallToolRequestSchema } from '@modelcontextprotocol/sdk/types.js';
import fs from 'fs';
import path from 'path';
import { trackUsage } from '../quota-manager.js';

// Mock dependencies
vi.mock('fs');
vi.mock('../quota-manager');

// Mock specific path methods we use
vi.spyOn(path, 'resolve').mockImplementation((...args) => args.join('/'));
vi.spyOn(path, 'join').mockImplementation((...args) => args.join('/'));

// Create a mock for Octokit
const mockCreateWorkflowDispatch = vi.fn();
vi.mock('octokit', () => ({
    Octokit: class {
        rest = {
            actions: {
                createWorkflowDispatch: mockCreateWorkflowDispatch
            }
        };
    }
}));

// We need to test the handler logic, but it's inside the main file which executes on import.
// For this test, we'll manually implement the logic we want to test since exporting the server 
// instance from index.ts might trigger execution.
// Ideally, we would refactor index.ts to export the handler functions for easier testing.

describe('trigger_autonomous_workflow logic', () => {
    const REPO_OWNER = "Techlemariam";
    const REPO_NAME = "IronForge";
    const workflow = "night-shift";
    const model = "gemini-2.5-flash";
    const cwd = "/test/cwd";

    beforeEach(() => {
        vi.clearAllMocks();
        vi.spyOn(process, 'cwd').mockReturnValue(cwd);
        vi.spyOn(path, 'resolve').mockImplementation((...args) => args.join('/'));
    });

    afterEach(() => {
        vi.restoreAllMocks();
    });

    it('should signal Antigravity when available', async () => {
        // Setup scenarios
        vi.spyOn(fs, 'existsSync').mockReturnValue(true); // Antigravity/Tasks dir exists
        vi.spyOn(fs, 'writeFileSync').mockReturnValue(undefined);

        // Emulate the logic from index.ts
        const taskDir = path.resolve(cwd, "../../.agent/tasks");
        const antigravityAvailable = fs.existsSync(taskDir);

        let result;
        if (antigravityAvailable) {
            const taskPath = path.join(taskDir, "current.md");
            const taskContent = `# Autonomous Mission: ${workflow}\nModel: ${model}\nTriggered via MCP at ${new Date().toISOString()}`;
            fs.writeFileSync(taskPath, taskContent);
            trackUsage(1);
            result = "antigravity";
        } else {
            result = "fallback";
        }

        // Assertions
        expect(fs.existsSync).toHaveBeenCalledWith(expect.stringContaining('.agent/tasks'));
        expect(fs.writeFileSync).toHaveBeenCalledWith(
            expect.stringContaining('current.md'),
            expect.stringContaining('# Autonomous Mission')
        );
        expect(trackUsage).toHaveBeenCalledWith(1);
        expect(result).toBe("antigravity");
        expect(mockCreateWorkflowDispatch).not.toHaveBeenCalled();
    });

    it('should fallback to GitHub Actions when Antigravity is unavailable', async () => {
        vi.spyOn(fs, 'existsSync').mockReturnValue(false); // Task dir does not exist
        vi.spyOn(fs, 'writeFileSync').mockReturnValue(undefined);

        // Emulate the logic
        const taskDir = path.resolve(cwd, "../../.agent/tasks");
        const antigravityAvailable = fs.existsSync(taskDir);

        let result;
        if (antigravityAvailable) {
            result = "antigravity";
        } else {
            await mockCreateWorkflowDispatch({
                owner: REPO_OWNER,
                repo: REPO_NAME,
                workflow_id: `autonomous-${workflow}.yml`,
                ref: "main",
                inputs: { workflow, model },
            });
            trackUsage(1);
            result = "fallback";
        }

        // Assertions
        expect(fs.existsSync).toHaveBeenCalled();
        expect(fs.writeFileSync).not.toHaveBeenCalled();
        expect(mockCreateWorkflowDispatch).toHaveBeenCalledWith(expect.objectContaining({
            owner: REPO_OWNER,
            repo: REPO_NAME,
            workflow_id: `autonomous-${workflow}.yml`
        }));
        expect(trackUsage).toHaveBeenCalledWith(1);
        expect(result).toBe("fallback");
    });
});

// @vitest-environment node
import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { getQuota, trackUsage, setQuotaFilePath } from '../quota-manager.js';
import fs from 'fs';
import path from 'path';
import os from 'os';

describe('quota-manager', () => {
    let tempFile: string;

    beforeEach(() => {
        // Create a temp file path unique for each test
        const tempDir = os.tmpdir();
        tempFile = path.join(tempDir, `quota_usage_${Date.now()}_${Math.random().toString(36).substring(7)}.json`);
        setQuotaFilePath(tempFile);
    });

    afterEach(() => {
        // Cleanup
        if (fs.existsSync(tempFile)) {
            try {
                fs.unlinkSync(tempFile);
            } catch (e) {
                // Ignore
            }
        }
    });

    describe('getQuota', () => {
        it('should return healthy status when quota file does not exist', () => {
            const result = getQuota();

            expect(result).toEqual({
                used: 0,
                remaining: 1500,
                percentUsed: 0,
                status: 'Healthy',
                source: 'antigravity'
            });
        });

        it('should return healthy status for new day', () => {
            const yesterday = new Date();
            yesterday.setDate(yesterday.getDate() - 1);
            const oldData = {
                date: yesterday.toISOString().split('T')[0],
                count: 1000
            };

            fs.writeFileSync(tempFile, JSON.stringify(oldData));

            const result = getQuota();

            expect(result).toEqual({
                used: 0,
                remaining: 1500,
                percentUsed: 0,
                status: 'Healthy',
                source: 'antigravity'
            });
        });

        it('should return warning status when usage > 75%', () => {
            const today = new Date().toISOString().split('T')[0];
            const data = {
                date: today,
                count: 1200 // 80% of 1500
            };

            fs.writeFileSync(tempFile, JSON.stringify(data));

            const result = getQuota();

            expect(result.status).toBe('Warning');
            expect(result.percentUsed).toBe(80);
            expect(result.source).toBe('antigravity');
        });

        it('should return healthy status when usage < 75%', () => {
            const today = new Date().toISOString().split('T')[0];
            const data = {
                date: today,
                count: 750 // 50% of 1500
            };

            fs.writeFileSync(tempFile, JSON.stringify(data));

            const result = getQuota();

            expect(result.status).toBe('Healthy');
            expect(result.percentUsed).toBe(50);
        });

        it('should return healthy/default status on error (corrupted file)', () => {
            fs.writeFileSync(tempFile, 'invalid-json');

            const result = getQuota();

            expect(result.status).toBe('Healthy');
            expect(result.source).toBe('unknown');
        });
    });

    describe('trackUsage', () => {
        it('should create new quota file for today', () => {
            const today = new Date().toISOString().split('T')[0];

            const result = trackUsage(1);

            expect(fs.existsSync(tempFile)).toBe(true);
            const writtenData = JSON.parse(fs.readFileSync(tempFile, 'utf-8'));
            expect(writtenData.date).toBe(today);
            expect(writtenData.count).toBe(1);
            expect(result.used).toBe(1);
        });

        it('should increment existing quota for today', () => {
            const today = new Date().toISOString().split('T')[0];
            const existingData = {
                date: today,
                count: 42
            };

            fs.writeFileSync(tempFile, JSON.stringify(existingData));

            const result = trackUsage(1);

            const writtenData = JSON.parse(fs.readFileSync(tempFile, 'utf-8'));
            expect(writtenData.count).toBe(43);
            expect(result.used).toBe(43);
        });

        it('should reset quota for new day', () => {
            const yesterday = new Date();
            yesterday.setDate(yesterday.getDate() - 1);
            const oldData = {
                date: yesterday.toISOString().split('T')[0],
                count: 1400
            };

            fs.writeFileSync(tempFile, JSON.stringify(oldData));

            const result = trackUsage(5);

            const writtenData = JSON.parse(fs.readFileSync(tempFile, 'utf-8'));
            expect(writtenData.count).toBe(5);
            expect(result.used).toBe(5);
        });

        it('should create directory if it does not exist', () => {
            // Use a subdirectory in temp
            const subDir = path.join(os.tmpdir(), `subdir_${Date.now()}_${Math.random().toString(36).substring(7)}`);
            const deepFile = path.join(subDir, 'quota.json');
            setQuotaFilePath(deepFile);

            try {
                trackUsage(1);
                expect(fs.existsSync(subDir)).toBe(true);
            } finally {
                if (fs.existsSync(deepFile)) fs.unlinkSync(deepFile);
                if (fs.existsSync(subDir)) fs.rmdirSync(subDir);
            }
        });

        it('should handle custom increment values', () => {
            trackUsage(10);

            const writtenData = JSON.parse(fs.readFileSync(tempFile, 'utf-8'));
            expect(writtenData.count).toBe(10);
        });
    });
});

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
    CallToolRequestSchema,
    ListToolsRequestSchema,
    ListResourcesRequestSchema,
    ReadResourceRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import { Octokit } from "octokit";
import { z } from "zod";
import { exec } from "child_process";
import { promisify } from "util";
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";
import { getQuota, trackUsage } from "./quota-manager.js";
import { startWebhookServer } from "./webhook-server.js";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const execAsync = promisify(exec);

// Environment variables
const GITHUB_TOKEN = process.env.GITHUB_TOKEN;
const REPO_OWNER = process.env.REPO_OWNER || "Techlemariam";
const REPO_NAME = process.env.REPO_NAME || "IronForge";

const octokit = new Octokit({ auth: GITHUB_TOKEN });

const server = new Server(
    {
        name: "ironforge-factory-mcp",
        version: "1.0.0",
    },
    {
        capabilities: {
            resources: {},
            tools: {},
        },
    }
);

// Helper to find the agent tasks directory
function getTaskDirectory(): string {
    // 1. Try environment variable
    if (process.env.AGENT_TASKS_DIR) {
        return process.env.AGENT_TASKS_DIR;
    }

    // 2. Try to find .agent/tasks relative to this script
    // We assume the standard structure: <workspace>/.agent/tasks
    // This script is usually at <workspace>/mcp/factory-server/build/index.js

    // Try to find workspace root by looking for .agent directory walking up
    let currentDir = __dirname;
    const root = path.parse(currentDir).root;

    while (currentDir !== root) {
        const agentDir = path.join(currentDir, ".agent");
        if (fs.existsSync(agentDir)) {
            return path.join(agentDir, "tasks");
        }
        currentDir = path.dirname(currentDir);
    }

    // 3. Fallback to hardcoded Antigravity path if we can't find it (Windows specific)
    const userProfile = process.env.USERPROFILE;
    if (userProfile) {
        const antigravityTasks = path.join(userProfile, ".gemini", "antigravity", "tasks"); // Guessing path
        // Better fallback: just use the CWD fallback but log warning
    }

    // 4. Fallback to original relative path logic (often fails if CWD is wrong)
    return path.resolve(process.cwd(), "../../.agent/tasks");
}

/**
 * Resources
 */
server.setRequestHandler(ListResourcesRequestSchema, async () => {
    return {
        resources: [
            {
                uri: "factory://status",
                name: "Factory Orchestration Status",
                mimeType: "application/json",
                description: "Aggregated health and metadata for all factory stations",
            },
            {
                uri: "factory://usage",
                name: "Gemini Quota Usage",
                mimeType: "application/json",
                description: "Daily token consumption metrics",
            },
            {
                uri: "factory://health",
                name: "MCP Server Health",
                mimeType: "application/json",
                description: "Health status of MCP server and Antigravity integration",
            },
        ],
    };
});

server.setRequestHandler(ReadResourceRequestSchema, async (request) => {
    const uri = request.params.uri;

    if (uri === "factory://usage") {
        return {
            contents: [
                {
                    uri,
                    mimeType: "application/json",
                    text: JSON.stringify(getQuota(), null, 2),
                },
            ],
        };
    }

    if (uri === "factory://status") {
        return {
            contents: [
                {
                    uri,
                    mimeType: "application/json",
                    text: JSON.stringify({ status: "operational", stations: 8 }, null, 2),
                },
            ],
        };
    }

    if (uri === "factory://health") {
        const taskDir = getTaskDirectory();

        let antigravityAvailable = false;
        try {
            antigravityAvailable = fs.existsSync(taskDir);
        } catch (e) {
            antigravityAvailable = false;
        }

        const health = {
            status: "healthy",
            timestamp: new Date().toISOString(),
            uptime: process.uptime(),
            antigravity: {
                available: antigravityAvailable,
                taskDirectory: taskDir,
                cwd: process.cwd(),
                dirname: __dirname
            },
            quota: getQuota(),
            mcp: {
                version: "1.0.0",
                server: "ironforge-factory-mcp",
                webhook_enabled: process.env.ENABLE_WEBHOOK_SERVER === "true",
                webhook_port: process.env.WEBHOOK_PORT || "3030"
            },
        };

        return {
            contents: [
                {
                    uri,
                    mimeType: "application/json",
                    text: JSON.stringify(health, null, 2),
                },
            ],
        };
    }

    throw new Error(`Resource not found: ${uri}`);
});

/**
 * Tools
 */
server.setRequestHandler(ListToolsRequestSchema, async () => {
    return {
        tools: [
            {
                name: "get_quota_status",
                description: "Checks the remaining Gemini API quota for the day based on local tracking.",
                inputSchema: { type: "object", properties: {} },
            },
            {
                name: "check_runner_health",
                description: "Executes the local runner health check script.",
                inputSchema: { type: "object", properties: {} },
            },
            {
                name: "trigger_autonomous_workflow",
                description: "Triggers a GitHub Action workflow or local signal depending on quota.",
                inputSchema: {
                    type: "object",
                    properties: {
                        workflow: {
                            type: "string",
                            enum: ["night-shift", "polish", "git-hygiene", "cleanup", "debt-attack", "security", "sprint-auto"],
                        },
                        model: {
                            type: "string",
                            enum: ["gemini-2.5-flash", "gemini-2.5-pro"],
                        },
                    },
                    required: ["workflow", "model"],
                },
            },
        ],
    };
});

server.setRequestHandler(CallToolRequestSchema, async (request) => {
    const { name, arguments: args } = request.params;

    switch (name) {
        case "get_quota_status": {
            const quota = getQuota();
            return {
                content: [
                    {
                        type: "text",
                        text: `Quota Status: ${quota.status}\nUsed: ${quota.used} / 1500\nRemaining: ${quota.remaining}\nUsage: ${quota.percentUsed}%`,
                    },
                ],
            };
        }

        case "check_runner_health": {
            try {
                const scriptPath = path.resolve(process.cwd(), "../../scripts/check-runner-health.ps1");
                const { stdout } = await execAsync(`powershell.exe -ExecutionPolicy Bypass -File "${scriptPath}"`);
                return {
                    content: [{ type: "text", text: stdout }],
                };
            } catch (error: any) {
                return {
                    content: [{ type: "text", text: `Health check failed: ${error.message}` }],
                    isError: true,
                };
            }
        }

        case "trigger_autonomous_workflow": {
            const { workflow, model } = args as { workflow: string; model: string };
            const quota = getQuota();

            // Quota-Aware Fallback Logic
            if (quota.status !== "Critical") {
                // Option A: Signal Antigravity via file
                const taskDir = getTaskDirectory();
                const taskPath = path.join(taskDir, "current.md");

                // Ensure directory exists
                if (!fs.existsSync(taskDir)) {
                    try {
                        fs.mkdirSync(taskDir, { recursive: true });
                    } catch (e) {
                        // Ignore, let write fail or fallback
                    }
                }

                if (fs.existsSync(taskDir)) {
                    const taskContent = `# Autonomous Mission: ${workflow}\nModel: ${model}\nTriggered via MCP at ${new Date().toISOString()}`;
                    fs.writeFileSync(taskPath, taskContent);
                    trackUsage(1);

                    return {
                        content: [{ type: "text", text: `Quota OK. Task signal written to ${taskPath} for Antigravity.` }],
                    };
                }
            }

            // Fallback (or if Option A failed/skipped)
            // Option B: Trigger directly via GitHub API (Octokit)
            try {
                await octokit.rest.actions.createWorkflowDispatch({
                    owner: REPO_OWNER,
                    repo: REPO_NAME,
                    workflow_id: "autonomous-antigravity-trigger.yml", // Corrected filename
                    ref: "main",
                    inputs: { workflow, model },
                });
                trackUsage(1);

                return {
                    content: [{ type: "text", text: `Triggered fallback via GitHub Actions workflow_dispatch.` }],
                };
            } catch (error: any) {
                return {
                    content: [{ type: "text", text: `Fallback trigger failed: ${error.message}` }],
                    isError: true,
                };
            }
        }

        default:
            throw new Error(`Tool not found: ${name}`);
    }
});

async function main() {
    const transport = new StdioServerTransport();
    await server.connect(transport);
    console.error("Factory MCP Server running on stdio");

    // Optionally start webhook server for external integrations
    if (process.env.ENABLE_WEBHOOK_SERVER === "true") {
        try {
            startWebhookServer();
            console.error(`Webhook server enabled on port ${process.env.WEBHOOK_PORT || 3030}`);
        } catch (e: any) {
            console.error(`Failed to start webhook server: ${e.message}`);
        }
    }
}

main().catch((error) => {
    console.error("Fatal error in main():", error);
    process.exit(1);
});

import fs from 'fs';
import path from 'path';

// Tracking file path relative to project root
// Tracking file path relative to project root
let quotaFilePath = path.resolve(process.cwd(), '../../.agent/quota_usage.json');
const DAILY_LIMIT = 1500; // Google One AI Pro typical daily RPD limit

export function setQuotaFilePath(path: string) {
    quotaFilePath = path;
}


export interface QuotaStatus {
    used: number;
    remaining: number;
    percentUsed: number;
    status: 'Healthy' | 'Warning' | 'Critical';
    source: 'antigravity' | 'unknown';
}

export function getQuota(): QuotaStatus {
    const today = new Date().toISOString().split('T')[0];

    if (!fs.existsSync(quotaFilePath)) {
        return { used: 0, remaining: DAILY_LIMIT, percentUsed: 0, status: 'Healthy', source: 'antigravity' };
    }

    try {
        const data = JSON.parse(fs.readFileSync(quotaFilePath, 'utf-8'));
        if (data.date !== today) {
            return { used: 0, remaining: DAILY_LIMIT, percentUsed: 0, status: 'Healthy', source: 'antigravity' };
        }

        const percent = (data.count / DAILY_LIMIT) * 100;
        return {
            used: data.count,
            remaining: Math.max(0, DAILY_LIMIT - data.count),
            percentUsed: Math.round(percent),
            status: percent > 90 ? 'Critical' : percent > 75 ? 'Warning' : 'Healthy',
            source: 'antigravity'
        };
    } catch (error) {
        console.error('Failed to read quota file:', error);
        return { used: 0, remaining: DAILY_LIMIT, percentUsed: 0, status: 'Healthy', source: 'unknown' };
    }
}

export function trackUsage(increment = 1): QuotaStatus {
    const today = new Date().toISOString().split('T')[0];
    let data = { date: today, count: 0 };

    if (fs.existsSync(quotaFilePath)) {
        try {
            const fileContent = JSON.parse(fs.readFileSync(quotaFilePath, 'utf-8'));
            if (fileContent.date === today) {
                data = fileContent;
            }
        } catch (e) {
            // If corrupted, reset
        }
    }

    data.count += increment;

    // Ensure directory exists
    const dir = path.dirname(quotaFilePath);
    if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
    }

    fs.writeFileSync(quotaFilePath, JSON.stringify(data, null, 2));

    const percent = (data.count / DAILY_LIMIT) * 100;
    return {
        used: data.count,
        remaining: Math.max(0, DAILY_LIMIT - data.count),
        percentUsed: Math.round(percent),
        status: percent > 90 ? 'Critical' : percent > 75 ? 'Warning' : 'Healthy',
        source: 'antigravity'
    };
}

import fs from 'fs';
import path from 'path';

/**
 * CI Forensic Annotator
 * Converts specialist doctor logs and JSON reports into GHA Annotations.
 */

async function annotate() {
    const reportPath = process.argv[2];
    if (!reportPath || !fs.existsSync(reportPath)) {
        console.log('::warning ::No forensic report found for annotation.');
        return;
    }

    const report = JSON.parse(fs.readFileSync(reportPath, 'utf8'));

    // Format: { issues: [ { file: string, line: number, message: string, severity: 'error' | 'warning' } ] }
    if (report.issues && Array.isArray(report.issues)) {
        for (const issue of report.issues) {
            const level = issue.severity === 'warning' ? 'warning' : 'error';
            console.log(`::${level} file=${issue.file},line=${issue.line},title=Forensic Finding::${issue.message}`);
        }
    }

    console.log('✅ Forensic annotations complete.');
}

annotate().catch(err => {
    console.error('::error ::Failed to generate annotations: ' + err.message);
    process.exit(1);
});

#!/usr/bin/env npx tsx
/**
 * CI Pipeline Analyzer v3.0
 *
 * Analyzes GitHub Actions workflow files for inefficiencies and suggests
 * optimizations: duplicate steps, cache misses, parallelization, redundant builds.
 *
 * Usage: npx tsx scripts/ci-pipeline-analyzer.ts [workflow-file]
 *        npx tsx scripts/ci-pipeline-analyzer.ts .github/workflows/ci-cd.yml
 */

import * as fs from 'fs';
import * as path from 'path';
import * as yaml from 'yaml'; // Note: requires yaml dep or use simple parser

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface Optimization {
    id: string;
    severity: 'HIGH' | 'MEDIUM' | 'LOW';
    category: 'duplication' | 'cache' | 'parallelization' | 'timing' | 'cost' | 'security';
    title: string;
    description: string;
    currentState: string;
    suggestedFix: string;
    estimatedSavings: string;
}

interface PipelineReport {
    file: string;
    totalJobs: number;
    totalSteps: number;
    optimizations: Optimization[];
    score: number; // 0-100
}

// ---------------------------------------------------------------------------
// Analyzers
// ---------------------------------------------------------------------------

function analyzeDuplicateSteps(content: string): Optimization[] {
    const optimizations: Optimization[] = [];

    // Count occurrences of common setup patterns
    const checkoutCount = (content.match(/actions\/checkout@/g) || []).length;
    const pnpmSetupCount = (content.match(/pnpm\/action-setup@/g) || []).length;
    const nodeSetupCount = (content.match(/actions\/setup-node@/g) || []).length;
    const installCount = (content.match(/pnpm install --frozen-lockfile/g) || []).length;
    const prismaGenCount = (content.match(/prisma generate/g) || []).length;

    if (checkoutCount > 2) {
        optimizations.push({
            id: 'DUP_CHECKOUT',
            severity: 'MEDIUM',
            category: 'duplication',
            title: `Checkout repeated ${checkoutCount}x across jobs`,
            description: `actions/checkout appears ${checkoutCount} times. Each checkout adds ~5-15s.`,
            currentState: `${checkoutCount} separate checkout steps`,
            suggestedFix: 'Use a composite action or reusable workflow to share checkout + setup.',
            estimatedSavings: `~${(checkoutCount - 1) * 10}s`,
        });
    }

    if (installCount > 2) {
        optimizations.push({
            id: 'DUP_INSTALL',
            severity: 'HIGH',
            category: 'duplication',
            title: `pnpm install repeated ${installCount}x`,
            description: `Each pnpm install takes 30-90s even with cache. Total overhead: ${installCount * 60}s.`,
            currentState: `${installCount} separate install steps`,
            suggestedFix: 'Create composite action: checkout → pnpm → node → install → prisma generate. Reuse across jobs.',
            estimatedSavings: `~${(installCount - 1) * 45}s`,
        });
    }

    if (prismaGenCount > 2) {
        optimizations.push({
            id: 'DUP_PRISMA',
            severity: 'MEDIUM',
            category: 'duplication',
            title: `Prisma generate repeated ${prismaGenCount}x`,
            description: `npx prisma generate runs in ${prismaGenCount} jobs. Could generate once and share via artifact.`,
            currentState: `${prismaGenCount} separate prisma generate steps`,
            suggestedFix: 'Generate Prisma client once in first job, upload as artifact, download in other jobs.',
            estimatedSavings: `~${(prismaGenCount - 1) * 15}s`,
        });
    }

    return optimizations;
}

function analyzeCaching(content: string): Optimization[] {
    const optimizations: Optimization[] = [];

    // Check for turbo cache
    if (content.includes('turbo') && !content.includes('.turbo')) {
        optimizations.push({
            id: 'CACHE_TURBO_MISSING',
            severity: 'HIGH',
            category: 'cache',
            title: 'Turbo cache not configured',
            description: 'Turborepo is used but .turbo cache directory is not cached between runs.',
            currentState: 'No turbo cache',
            suggestedFix: 'Add actions/cache for .turbo directory with content-hash key.',
            estimatedSavings: '~60-120s on subsequent runs',
        });
    }

    // Check cache key strategy
    if (content.includes('github.sha') && content.includes('actions/cache')) {
        optimizations.push({
            id: 'CACHE_KEY_SHA',
            severity: 'LOW',
            category: 'cache',
            title: 'Cache key uses exact SHA (low hit rate)',
            description: 'Using github.sha as cache key means cache only hits on re-runs, not new commits.',
            currentState: `key: turbo-\${{ runner.os }}-\${{ github.sha }}`,
            suggestedFix: 'Use hashFiles for primary key, SHA for restore-keys fallback.',
            estimatedSavings: '~30-60s cache hit improvement',
        });
    }

    // Check playwright cache
    if (content.includes('playwright') && !content.includes('ms-playwright')) {
        optimizations.push({
            id: 'CACHE_PLAYWRIGHT_MISSING',
            severity: 'MEDIUM',
            category: 'cache',
            title: 'Playwright browsers not cached',
            description: 'Playwright browser download takes 60-120s. Should be cached.',
            currentState: 'No playwright cache',
            suggestedFix: 'Cache ~/.cache/ms-playwright with pnpm-lock.yaml hash key.',
            estimatedSavings: '~60-120s',
        });
    }

    return optimizations;
}

function analyzeParallelization(content: string): Optimization[] {
    const optimizations: Optimization[] = [];

    // Check if turbo steps are split
    const turboSteps = (content.match(/turbo run \w+/g) || []);
    if (turboSteps.length > 3) {
        optimizations.push({
            id: 'PARALLEL_TURBO_SPLIT',
            severity: 'MEDIUM',
            category: 'parallelization',
            title: `${turboSteps.length} separate turbo run commands`,
            description: `Each turbo run has startup overhead. Combine into single turbo pipeline.`,
            currentState: turboSteps.map(s => `  ${s}`).join('\n'),
            suggestedFix: 'Combine: npx turbo run lint check-types test build security --concurrency=100%',
            estimatedSavings: '~15-30s turbo startup overhead',
        });
    }

    // Check for sequential builds that could be parallel
    if (content.includes('needs:') && content.includes('perf-audit')) {
        // Check if perf-audit depends on verify or runs independently
        if (!content.match(/perf-audit[\s\S]*?needs.*verify/)) {
            optimizations.push({
                id: 'PARALLEL_PERF',
                severity: 'LOW',
                category: 'parallelization',
                title: 'perf-audit runs independently but rebuilds',
                description: 'perf-audit does its own build. Could reuse build artifact from verify job.',
                currentState: 'Independent build in perf-audit',
                suggestedFix: 'Upload build artifact from verify, download in perf-audit (skip duplicate build).',
                estimatedSavings: '~60-90s build time',
            });
        }
    }

    return optimizations;
}

function analyzeTiming(content: string): Optimization[] {
    const optimizations: Optimization[] = [];

    // Check for static sleep commands
    const sleepMatches = content.match(/sleep \d+/g) || [];
    if (sleepMatches.length > 0) {
        const totalSleep = sleepMatches.reduce((sum, s) => sum + parseInt(s.split(' ')[1], 10), 0);
        optimizations.push({
            id: 'TIMING_STATIC_SLEEP',
            severity: 'HIGH',
            category: 'timing',
            title: `${sleepMatches.length} static sleep commands (${totalSleep}s total)`,
            description: `Static sleeps waste time. Replace with health-check loops.`,
            currentState: sleepMatches.join(', '),
            suggestedFix: `Replace 'sleep N' with: while ! pg_isready -h 127.0.0.1 -U postgres; do sleep 2; done`,
            estimatedSavings: `Up to ~${Math.floor(totalSleep * 0.5)}s on average`,
        });
    }

    // Check timeout settings
    if (!content.includes('timeout-minutes')) {
        optimizations.push({
            id: 'TIMING_NO_TIMEOUT',
            severity: 'MEDIUM',
            category: 'timing',
            title: 'No job timeout configured',
            description: 'Jobs without timeout-minutes can run indefinitely on hung processes.',
            currentState: 'No timeout-minutes set',
            suggestedFix: 'Add timeout-minutes: 30 to each job to prevent runaway costs.',
            estimatedSavings: 'Prevents runaway billing',
        });
    }

    return optimizations;
}

function analyzeSecurity(content: string): Optimization[] {
    const optimizations: Optimization[] = [];

    // Check for pinned action versions
    const unpinnedActions = content.match(/uses: [^@]+@v\d+$/gm) || [];
    // Check for hash-pinned actions
    const hashPinned = content.match(/uses: [^@]+@[a-f0-9]{40}/gm) || [];

    if (unpinnedActions.length > 0 && hashPinned.length === 0) {
        optimizations.push({
            id: 'SEC_UNPINNED_ACTIONS',
            severity: 'LOW',
            category: 'security',
            title: 'Actions use tag versions instead of SHA pins',
            description: 'Tag-based versions (e.g., @v4) can be moved. SHA-pinning prevents supply chain attacks.',
            currentState: `${unpinnedActions.length} tag-versioned actions`,
            suggestedFix: 'Pin critical actions to SHA: e.g., actions/checkout@<sha>',
            estimatedSavings: 'Improved supply chain security',
        });
    }

    // Check for environment variable exposure
    if (content.includes('secrets.') && content.includes('echo')) {
        optimizations.push({
            id: 'SEC_SECRET_ECHO',
            severity: 'MEDIUM',
            category: 'security',
            title: 'Potential secret exposure in echo/log output',
            description: 'Secrets used near echo commands could be accidentally logged.',
            currentState: 'echo commands near secret references',
            suggestedFix: 'Use ::add-mask:: for dynamic secrets. Never echo ${{ secrets.* }}.',
            estimatedSavings: 'Prevents secret exposure',
        });
    }

    return optimizations;
}

// ---------------------------------------------------------------------------
// Main Analyzer
// ---------------------------------------------------------------------------

export function analyzeWorkflow(filePath: string): PipelineReport {
    const content = fs.readFileSync(filePath, 'utf-8');

    // Count jobs and steps
    const jobMatches = content.match(/^\s{2}\w[\w-]*:/gm) || [];
    const stepMatches = content.match(/- name:/g) || [];

    const optimizations: Optimization[] = [
        ...analyzeDuplicateSteps(content),
        ...analyzeCaching(content),
        ...analyzeParallelization(content),
        ...analyzeTiming(content),
        ...analyzeSecurity(content),
    ];

    // Calculate score (100 = perfect, deduct for each issue)
    const deductions = optimizations.reduce((sum, opt) => {
        switch (opt.severity) {
            case 'HIGH': return sum + 15;
            case 'MEDIUM': return sum + 8;
            case 'LOW': return sum + 3;
            default: return sum;
        }
    }, 0);

    return {
        file: filePath,
        totalJobs: jobMatches.length,
        totalSteps: stepMatches.length,
        optimizations,
        score: Math.max(0, 100 - deductions),
    };
}

// ---------------------------------------------------------------------------
// Formatters
// ---------------------------------------------------------------------------

function formatReport(report: PipelineReport): string {
    let output = '\n╔══════════════════════════════════════════════════════════════╗\n';
    output += '║        🏎️ CI PIPELINE OPTIMIZER — ANALYSIS REPORT            ║\n';
    output += '╚══════════════════════════════════════════════════════════════╝\n\n';

    output += `📂 File: ${report.file}\n`;
    output += `📊 Jobs: ${report.totalJobs} | Steps: ${report.totalSteps}\n`;
    output += `🏆 Pipeline Score: ${report.score}/100\n\n`;

    if (report.optimizations.length === 0) {
        output += '✅ No optimizations found. Pipeline is well-configured!\n';
        return output;
    }

    const byCategory = new Map<string, Optimization[]>();
    for (const opt of report.optimizations) {
        const list = byCategory.get(opt.category) || [];
        list.push(opt);
        byCategory.set(opt.category, list);
    }

    for (const [category, opts] of byCategory) {
        const icon = { duplication: '📋', cache: '💾', parallelization: '⚡', timing: '⏱️', cost: '💰', security: '🔒' }[category] || '📌';
        output += `${icon} ${category.toUpperCase()}\n`;
        output += '─'.repeat(60) + '\n';

        for (const opt of opts) {
            const sevIcon = opt.severity === 'HIGH' ? '🔴' : opt.severity === 'MEDIUM' ? '🟡' : '🟢';
            output += `  ${sevIcon} ${opt.title}\n`;
            output += `     Current: ${opt.currentState}\n`;
            output += `     Fix: ${opt.suggestedFix}\n`;
            output += `     Savings: ${opt.estimatedSavings}\n\n`;
        }
    }

    return output;
}

// ---------------------------------------------------------------------------
// CLI
// ---------------------------------------------------------------------------

function main() {
    const args = process.argv.slice(2);
    const jsonMode = args.includes('--json');
    const filteredArgs = args.filter(a => a !== '--json');

    // Default to ci-cd.yml if no file specified
    const targetFile = filteredArgs[0] || '.github/workflows/ci-cd.yml';
    const resolvedPath = path.resolve(targetFile);

    if (!fs.existsSync(resolvedPath)) {
        console.error(`Error: File not found: ${resolvedPath}`);
        process.exit(1);
    }

    const report = analyzeWorkflow(resolvedPath);

    if (jsonMode) {
        console.log(JSON.stringify(report, null, 2));
    } else {
        console.log(formatReport(report));
    }

    // Save report
    const reportDir = path.join(process.cwd(), '.agent', 'reports', 'ci-doctor');
    if (!fs.existsSync(reportDir)) {
        fs.mkdirSync(reportDir, { recursive: true });
    }
    const reportFile = path.join(reportDir, `pipeline-${new Date().toISOString().replace(/[:.]/g, '-')}.json`);
    fs.writeFileSync(reportFile, JSON.stringify(report, null, 2));
    console.log(`\n📁 Report saved: ${reportFile}`);

    // Exit with non-zero if score is below threshold
    if (report.score < 50) {
        process.exit(1);
    }
}

main();

#!/usr/bin/env npx tsx
/**
 * Agent Workflow Analyzer
 *
 * Audits .agent/workflows/*.md files for:
 * 1. Metadata validity (frontmatter)
 * 2. Turbo optimization opportunities (auto-run safe commands)
 * 3. Skill usage consistency
 *
 * Usage:
 *   npx tsx scripts/workflow-analyzer.ts [--fix]
 */

import * as fs from 'fs';
import * as path from 'path';

const WORKFLOW_DIR = path.join(process.cwd(), '.agent', 'workflows');
const SKILL_DIR = path.join(process.cwd(), '.agent', 'skills');

interface Issue {
    file: string;
    line?: number;
    severity: 'HIGH' | 'MEDIUM' | 'LOW';
    type: 'METADATA' | 'TURBO' | 'SKILL' | 'FORMAT';
    message: string;
    autoFixable: boolean;
}

interface WorkflowStats {
    total: number;
    optimized: number;
    issues: Issue[];
}

function parseFrontmatter(content: string): Record<string, any> | null {
    const match = content.match(/^---\r?\n([\s\S]*?)\r?\n---/);
    if (!match) return null;

    const yaml = match[1];
    const meta: Record<string, any> = {};

    yaml.split('\n').forEach(line => {
        const parts = line.split(':');
        if (parts.length >= 2) {
            const key = parts[0].trim();
            // Handle arrays for skills
            if (key === 'skills') {
                const value = parts.slice(1).join(':').trim();
                // Remove brackets and split
                const cleanValue = value.replace(/^\[|\]$/g, '');
                meta[key] = cleanValue.split(',').map(s => s.trim().replace(/^['"]|['"]$/g, '')).filter(s => s.length > 0);
            } else {
                const value = parts.slice(1).join(':').trim().replace(/^['"](.*)['"]$/, '$1'); // simple unquote
                meta[key] = value;
            }
        }
    });

    return meta;
}

function getKnownSkills(): Set<string> {
    const skills = new Set<string>();

    // 1. Standard Skills
    if (fs.existsSync(SKILL_DIR)) {
        const entries = fs.readdirSync(SKILL_DIR, { withFileTypes: true });
        for (const entry of entries) {
            if (entry.isDirectory()) {
                skills.add(entry.name);
            }
        }
    }

    // 2. Github Workflows (treated as skills/capabilities)
    const githubWorkflowDir = path.join(process.cwd(), '.github', 'workflows');
    if (fs.existsSync(githubWorkflowDir)) {
        const entries = fs.readdirSync(githubWorkflowDir);
        for (const entry of entries) {
            if (entry.endsWith('.yml') || entry.endsWith('.yaml')) {
                skills.add(entry.replace('.yml', '').replace('.yaml', ''));
            }
        }
    }

    // 3. Agent Workflows (treated as skills/capabilities)
    if (fs.existsSync(WORKFLOW_DIR)) {
        const entries = fs.readdirSync(WORKFLOW_DIR);
        for (const entry of entries) {
            if (entry.endsWith('.md')) {
                skills.add(entry.replace('.md', ''));
            }
        }
    }

    // 4. Whitelisted Core Tools/Concepts
    skills.add('browser_subagent');
    skills.add('run_command');
    skills.add('npm'); // Core tool
    skills.add('pnpm'); // Core tool

    return skills;
}
function analyzeFile(filePath: string, fixMode: boolean, knownSkills: Set<string>): Issue[] {
    const issues: Issue[] = [];
    let content = fs.readFileSync(filePath, 'utf-8');
    const originalContent = content;
    const filename = path.basename(filePath);

    // 1. Frontmatter Check
    const meta = parseFrontmatter(content);
    if (!meta) {
        issues.push({
            file: filename,
            severity: 'HIGH',
            type: 'FORMAT',
            message: 'Invalid or missing YAML frontmatter',
            autoFixable: false
        });
        return issues;
    }

    // Check required fields
    const required = ['description', 'command', 'category', 'trigger'];
    for (const field of required) {
        if (!meta[field]) {
            issues.push({
                file: filename,
                severity: 'HIGH',
                type: 'METADATA',
                message: `Missing frontmatter field: ${field}`,
                autoFixable: false
            });
        }
    }

    // Check command match
    const expectedCmd = `/${filename.replace('.md', '')}`;
    if (meta.command && meta.command !== expectedCmd) {
        // Soft warning, some files like INDEX.md might differ
        if (filename !== 'INDEX.md' && !filename.startsWith('monitor-')) {
            issues.push({
                file: filename,
                severity: 'LOW',
                type: 'METADATA',
                message: `Command '${meta.command}' matches filename (expected '${expectedCmd}')?`,
                autoFixable: true
            });
        }
    }

    // 2. Skill Validation
    const declaredSkills = new Set<string>(Array.isArray(meta.skills) ? meta.skills : []);
    const bodyContent = content.replace(/^---\r?\n[\s\S]*?\r?\n---/, ''); // Remove frontmatter

    // Core tools that might be listed as skills but aren't in .agent/skills
    const coreTools = new Set(['browser_subagent', 'run_command', 'read_file', 'view_file', 'ask_user', 'notify_user', 'search_web']);

    // 2.1 check for invalid and unused skills
    for (const skill of declaredSkills) {
        if (!knownSkills.has(skill) && !coreTools.has(skill)) {
            issues.push({
                file: filename,
                severity: 'MEDIUM',
                type: 'SKILL',
                message: `Unknown skill declared: '${skill}'`,
                autoFixable: false
            });
            continue;
        }

        // Check usage (generous heuristic)
        // We assume usage if the skill name appears in the body OR a slash command /skill-name appears
        // Or if it's a common alias? For now, exact match.
        // We look for "skill-name" or "/skill-name"
        const regex = new RegExp(`\\b${skill}\\b|/${skill}`, 'i');
        if (!regex.test(bodyContent)) {
            issues.push({
                file: filename,
                severity: 'LOW',
                type: 'SKILL',
                message: `Skill declared but potentially unused: '${skill}'`,
                autoFixable: false
            });
        }
    }

    // 2.2 check for undeclared skills (slash commands)
    // Find all /something strings
    const slashCommands = bodyContent.matchAll(/\s\/([a-z0-9-]+)/g);
    const selfCommand = meta.command ? meta.command.replace('/', '') : filename.replace('.md', '');

    for (const match of slashCommands) {
        const cmd = match[1];

        // Ignore self-reference (e.g. /sync-project inside sync-project.md)
        if (cmd === selfCommand) continue;

        // If this command matches a known skill name, it should be declared
        if (knownSkills.has(cmd) && !declaredSkills.has(cmd)) {
            issues.push({
                file: filename,
                severity: 'MEDIUM',
                type: 'SKILL',
                message: `Skill used via command '/${cmd}' but not declared in frontmatter`,
                autoFixable: true
            });

            if (fixMode) {
                // Not implementing auto-fix for frontmatter yet as it's complex to preserve formatting
                // But we flag it as autoFixable for future
            }
        }
    }

    // 3. Logic Validation (Heuristic)
    let codeBlocks = (content.match(/```[\s\S]*?```/g) || []).join('\n');

    // 3.0 Enforce PNPM (Project Standard)
    if (/\bnpm (install|run|test|ci|start|build)\b/.test(codeBlocks)) {
        issues.push({
            file: filename,
            severity: 'MEDIUM',
            type: 'LOGIC',
            message: `Project uses pnpm, but 'npm' command found. Replace with 'pnpm'.`,
            autoFixable: true
        });
        if (fixMode) {
            // Smart replacements
            content = content
                .replace(/\bnpm ci\b/g, 'pnpm install --frozen-lockfile')
                .replace(/\bnpm (install|run|test|start|build)\b/g, 'pnpm $1');
        }
    }

    // 3.1 Check for build before install
    // Only warn if it looks like a CI/setup script (contains 'checkout' or 'setup')
    // OR if it's a completely isolated script.
    // We'll relax this check for now to avoid noise on manual debug workflows.
    if (/pnpm build/.test(codeBlocks)) {
        if (!/pnpm install|pnpm i\b/.test(codeBlocks) && /actions\/checkout/.test(content)) {
            issues.push({
                file: filename,
                severity: 'LOW',
                type: 'LOGIC',
                message: `CI workflow has build but no explicit install.`,
                autoFixable: false
            });
        }
    }

    // 3.2 Check for git commit before add
    // Rigid check: if 'git commit' exists, 'git add' should ideally exist or be handled.
    if (/git commit/.test(codeBlocks) && !/git add/.test(codeBlocks)) {
        issues.push({
            file: filename,
            severity: 'LOW',
            type: 'LOGIC',
            message: `Git commit found but no git add detected. Ensure stage is handled.`,
            autoFixable: false
        });
    }

    // 3.3 Check for secrets
    if (/sk_live_|ghp_|gho_|xoxb-|xoxp-/.test(content)) {
        issues.push({
            file: filename,
            severity: 'HIGH',
            type: 'SECURITY',
            message: `Potential hardcoded secret detected.`,
            autoFixable: false
        });
    }

    // 4. Turbo Opportunities
    // Look for bash code blocks without // turbo
    const lines = content.split('\n');
    let codeBlockOpen = false;
    let insideBash = false;
    let justSawTurbo = false;
    let contentChanged = false;

    // Check if content was already changed by pnpm fix
    if (originalContent !== content) {
        contentChanged = true;
    }

    // Simple state machine
    for (let i = 0; i < lines.length; i++) {
        const line = lines[i].trim();

        if (line.startsWith('```bash') || line.startsWith('```sh') || line.startsWith('```powershell')) {
            codeBlockOpen = true;
            insideBash = true;
            // Check previous line for // turbo
            const prevLine = lines[i - 1]?.trim() || '';
            const isTurbo = prevLine === '// turbo';

            // Heuristic for "safe to auto-run"
            // If the code block contains simple commands and no placeholders, it's a candidate
            // For now, we only flag if we detect "safe" keywords in the block content
            // We need to look ahead to find the content
            let blockContent = '';
            let j = i + 1;
            while (j < lines.length && !lines[j].startsWith('```')) {
                blockContent += lines[j] + '\n';
                j++;
            }

            const isSafe = blockContent.match(/^(ls|dir|echo|Get-Date|Write-Host|npx|npm|pnpm|git status)/m) && !blockContent.includes('rm ') && !blockContent.includes('sudo ');

            if (!isTurbo && isSafe) {
                issues.push({
                    file: filename,
                    line: i + 1,
                    severity: 'MEDIUM',
                    type: 'TURBO',
                    message: 'Code block could be auto-run (missing // turbo)',
                    autoFixable: true
                });

                if (fixMode) {
                    lines.splice(i, 0, '// turbo');
                    i++; // adjust index
                    contentChanged = true; // Mark as changed due to turbo fix
                }
            }
        } else if (line.startsWith('```')) {
            codeBlockOpen = false;
            insideBash = false;
        }
    }

    // Updated write condition:
    if (fixMode && (contentChanged || issues.some(i => i.autoFixable))) {
        fs.writeFileSync(filePath, lines.join('\n'));
    }

    return issues;
}

function generateGraph(files: string[]): string {
    const nodes: Record<string, { agent: string, command: string, triggers: string[] }> = {};
    const edges: string[] = [];
    const agents = new Set<string>();

    // 1. Parse all files to build nodes
    for (const file of files) {
        const content = fs.readFileSync(path.join(WORKFLOW_DIR, file), 'utf-8');
        const meta = parseFrontmatter(content);
        if (!meta) continue;

        const name = file.replace('.md', '');
        const agent = meta.primary_agent || 'unknown';
        const command = meta.command || `/${name}`;

        nodes[name] = { agent, command, triggers: [] };
        if (agent !== 'unknown') agents.add(agent);

        // Parse triggers from body
        const body = content.replace(/^---\r?\n[\s\S]*?\r?\n---/, '');
        const slashCommands = body.matchAll(/\s(\/[a-z0-9-]+)/g);
        for (const match of slashCommands) {
            const targetCmd = match[1];
            // Find which workflow has this command
            // We need a second pass or look up in a map if we had one.
            // For now, store the trigger and resolve later
            nodes[name].triggers.push(targetCmd);
        }
    }

    // 2. Build edges
    // Reverse map command -> file
    const cmdToFile: Record<string, string> = {};
    for (const [file, data] of Object.entries(nodes)) {
        cmdToFile[data.command] = file;
    }

    for (const [file, data] of Object.entries(nodes)) {
        for (const triggerCmd of data.triggers) {
            const targetFile = cmdToFile[triggerCmd];
            if (targetFile && targetFile !== file) {
                edges.push(`  ${file} -->|calls| ${targetFile}`);
            }
        }
    }

    // 3. Generate Mermaid
    let mermaid = 'graph TD\n';

    // Subgraphs for agents
    for (const agent of agents) {
        const agentName = agent.replace('@', '');
        mermaid += `  subgraph ${agentName} [${agent}]\n`;
        for (const [file, data] of Object.entries(nodes)) {
            if (data.agent === agent) {
                mermaid += `    ${file}("${file}<br/>${data.command}")\n`;
            }
        }
        mermaid += '  end\n';
    }

    // Nodes without agent
    for (const [file, data] of Object.entries(nodes)) {
        if (data.agent === 'unknown') {
            mermaid += `  ${file}("${file}")\n`;
        }
    }

    // Edges
    edges.forEach(edge => mermaid += edge + '\n');

    return mermaid;
}

function main() {
    const args = process.argv.slice(2);
    const fixMode = args.includes('--fix');
    const graphMode = args.includes('--graph');

    if (!fs.existsSync(WORKFLOW_DIR)) {
        console.error(`Dir not found: ${WORKFLOW_DIR}`);
        process.exit(1);
    }

    const files = fs.readdirSync(WORKFLOW_DIR).filter(f => f.endsWith('.md') && !f.startsWith('_'));
    const knownSkills = getKnownSkills();

    if (graphMode) {
        console.log('📊 Generating Knowledge Graph...');
        const mermaid = generateGraph(files);
        const graphPath = path.join(WORKFLOW_DIR, 'GRAPH.md');

        const graphContent = `# 🗺️ Agent Workflow Graph\n\nAuto-generated by \`workflow-analyzer.ts\`.\n\n\`\`\`mermaid\n${mermaid}\`\`\`\n`;

        fs.writeFileSync(graphPath, graphContent);
        console.log(`✅ Graph saved to ${graphPath}`);
        return;
    }

    let allIssues: Issue[] = [];

    console.log(`🔍 Analyzing ${files.length} agent workflows against ${knownSkills.size} skills...\n`);

    for (const file of files) {
        const issues = analyzeFile(path.join(WORKFLOW_DIR, file), fixMode, knownSkills);
        allIssues = [...allIssues, ...issues];
    }

    // Report
    const grouped = allIssues.reduce((acc, issue) => {
        acc[issue.file] = acc[issue.file] || [];
        acc[issue.file].push(issue);
        return acc;
    }, {} as Record<string, Issue[]>);

    for (const [file, issues] of Object.entries(grouped)) {
        console.log(`📄 ${file}`);
        for (const i of issues) {
            const icon = i.severity === 'HIGH' ? '🔴' : i.severity === 'MEDIUM' ? '🟡' : '🔵';
            console.log(`  ${icon} [${i.type}] ${i.message}`);
        }
        console.log('');
    }

    if (allIssues.length === 0) {
        console.log('✅ All workflows are optimized!');
    } else {
        console.log(`Found ${allIssues.length} issues.`);
        if (!fixMode) console.log('Run with --fix to apply auto-fixes.');
    }
}

