"use client";

import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';


import { RenderVideoPresenter } from './RenderVideoPresenter';

const defaultProps = {
  username: "TestUser",
  weekNumber: 1,
  strengthGains: 100
};

export function RenderVideoForm() {
  const [propsJson, setPropsJson] = useState(JSON.stringify(defaultProps, null, 2));
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<{ message: string; videoPath?: string; error?: string } | null>(null);

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    setIsLoading(true);
    setResult(null);

    let props;
    try {
      props = JSON.parse(propsJson);
    } catch (error) {
      setIsLoading(false);
      setResult({ message: 'Fel:', error: 'Ogiltig JSON. Kontrollera din indata.' });
      return;
    }

    try {
      const response = await fetch('/api/factory/render-video', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ props }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'Något gick fel på servern.');
      }

      setResult({ message: data.message, videoPath: data.videoPath });

    } catch (error: any) {
      setResult({ message: 'Fel vid anrop till API:', error: error.message });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <RenderVideoPresenter
      propsJson={propsJson}
      isLoading={isLoading}
      result={result}
      onPropsChange={setPropsJson}
      onSubmit={handleSubmit}
    />
  );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { Mic, MicOff, Send, Loader2, Sparkles } from 'lucide-react';
import { addFactoryTask } from '@/actions/factory';
import { useRouter } from 'next/navigation';

import { VoiceCommandPresenter } from './VoiceCommandPresenter';

export function VoiceCommandControl() {
    const [isListening, setIsListening] = useState(false);
    const [transcript, setTranscript] = useState('');
    const [isProcessing, setIsProcessing] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const recognitionRef = useRef<any>(null);
    const router = useRouter();

    useEffect(() => {
        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        if (SpeechRecognition) {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = true;
            recognitionRef.current.lang = 'sv-SE';

            recognitionRef.current.onresult = (event: any) => {
                const currentTranscript = Array.from(event.results)
                    .map((result: any) => result[0])
                    .map((result) => result.transcript)
                    .join('');
                setTranscript(currentTranscript);
            };

            recognitionRef.current.onerror = (event: any) => {
                console.error('Speech recognition error:', event.error);
                setError(`Mikrofonfel: ${event.error}`);
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } else {
            setError('Web Speech API stöds inte i denna webbläsare.');
        }

        return () => {
            if (recognitionRef.current) {
                recognitionRef.current.stop();
            }
        };
    }, []);

    const toggleListening = () => {
        if (isListening) {
            recognitionRef.current?.stop();
        } else {
            setTranscript('');
            setError(null);
            recognitionRef.current?.start();
            setIsListening(true);
        }
    };

    const handleSubmit = async () => {
        if (!transcript.trim() || isProcessing) return;

        setIsProcessing(true);
        try {
            const result = await addFactoryTask(transcript, 'WEB_UI', {
                userAgent: navigator.userAgent,
                timestamp: new Date().toISOString()
            });

            if (result.success) {
                setTranscript('');
                router.refresh();
            } else {
                setError('Kunde inte spara uppgiften.');
            }
        } catch (err) {
            setError('Ett fel uppstod vid kommunikation med servern.');
        } finally {
            setIsProcessing(false);
        }
    };

    return (
        <VoiceCommandPresenter
            isListening={isListening}
            transcript={transcript}
            isProcessing={isProcessing}
            error={error}
            onToggleListening={toggleListening}
            onSubmit={handleSubmit}
        />
    );
}

