import React, { useState, useEffect, useRef } from "react";
import { RaidBoss, ChatMessage } from "../../types";
import {
  // Skull removed
  Swords,
  Shield,
  Users,
  Send,
  Info,
  WifiOff,
  Zap,
  DoorOpen,
} from "lucide-react";
import { cn } from "../../lib/utils";
import { createClient } from "@/utils/supabase/client";
import { RealtimeChannel } from "@supabase/supabase-js";
import {
  sendChatAction,
  attackBossAction,
  getUserStatsAction,
} from "@/actions/guild/core";
import { motion } from "framer-motion";

interface GuildHallProps {
  onClose: () => void;
}

const DEFAULT_BOSS: RaidBoss = {
  id: "boss_iron_golem",
  name: "The Iron Golem",
  totalHp: 1000000,
  currentHp: 1000000,
  image: "🦾",
  description:
    "A massive automaton forged in the heart of the Iron Mines. It grows stronger with every failed attempt.",
  rewards: ["Kinetic Shard x50", "Golem Core", "Title: Golem Smasher"],
};

const ATTACK_COST = 5;

interface FloatingText {
  id: number;
  text: string;
  x: number;
  y: number;
  color: string;
}

export const GuildHall: React.FC<GuildHallProps> = ({ onClose }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState("");
  const [boss, setBoss] = useState<RaidBoss>(DEFAULT_BOSS);
  const [isConnected, setIsConnected] = useState(false);
  const [onlineCount, setOnlineCount] = useState(1);

  // Performance Coach State
  const [kineticEnergy, setKineticEnergy] = useState<number>(0);
  // const [_heroName, setHeroName] = useState<string>("Titan");

  // Visual Juice State
  const [floatingTexts, setFloatingTexts] = useState<FloatingText[]>([]);
  const [shake, setShake] = useState(false);

  // Animation state
  const [hpAnim, setHpAnim] = useState(boss.currentHp);

  const channelRef = useRef<RealtimeChannel | null>(null);

  // Initial Load & Subscription
  useEffect(() => {
    let mounted = true;

    const init = async () => {
      const supabase = createClient();
      setIsConnected(true);

      // Fetch User Stats (Ammo)
      const userStats = await getUserStatsAction();
      if (userStats && mounted) {
        setKineticEnergy(userStats.kineticEnergy);
        // setHeroName(userStats.heroName || "Titan");
      }

      // 1. Fetch Initial Boss State
      const { data: bossData } = await supabase
        .from("raid_bosses")
        .select("*")
        .eq("is_active", true)
        .single();

      if (bossData) {
        const mappedBoss: RaidBoss = {
          id: bossData.id,
          name: bossData.name,
          totalHp: bossData.total_hp,
          currentHp: bossData.current_hp,
          image: bossData.image,
          description: bossData.description,
          rewards: bossData.rewards,
        };
        if (mounted) {
          setBoss(mappedBoss);
          setHpAnim(mappedBoss.currentHp);
        }
      }

      // 2. Fetch Recent Chat
      const { data: chatData } = await supabase
        .from("chat_messages")
        .select("*")
        .order("timestamp", { ascending: false })
        .limit(50);

      if (chatData && mounted) {
        const mappedMessages = chatData.map((msg: any) => ({
          id: msg.id,
          userName: msg.user_name,
          message: msg.message,
          timestamp: msg.timestamp,
          type: msg.type,
        }));
        setMessages(mappedMessages.reverse());
      }

      // 3. Subscribe to Changes
      const channel = supabase
        .channel("guild_hall_global")
        .on(
          "postgres_changes",
          {
            event: "UPDATE",
            schema: "public",
            table: "raid_bosses",
            filter: `id=eq.${bossData?.id || DEFAULT_BOSS.id}`,
          },
          (payload) => {
            const newHp = payload.new.current_hp;
            if (mounted) {
              setBoss((prev) => ({ ...prev, currentHp: newHp }));
            }
          },
        )
        .on(
          "postgres_changes",
          { event: "INSERT", schema: "public", table: "chat_messages" },
          (payload) => {
            const newMsgRaw = payload.new;
            const newMsg: ChatMessage = {
              id: newMsgRaw.id,
              userName: newMsgRaw.user_name,
              message: newMsgRaw.message,
              timestamp: newMsgRaw.timestamp,
              type: newMsgRaw.type,
            };

            if (mounted) {
              setMessages((prev) => [...prev, newMsg]);
            }
          },
        )
        .on("presence", { event: "sync" }, () => {
          const state = channel.presenceState();
          if (mounted) setOnlineCount(Object.keys(state).length + 1);
        })
        .subscribe();

      await channel.track({ online_at: new Date().toISOString() });
      channelRef.current = channel;
    };

    init();

    return () => {
      mounted = false;
      if (channelRef.current) {
        channelRef.current.unsubscribe();
      }
    };
  }, []);

  // Lerp HP for smooth animation
  useEffect(() => {
    const interval = setInterval(() => {
      setHpAnim((prev) => {
        const diff = boss.currentHp - prev;
        if (Math.abs(diff) < 1) return boss.currentHp;
        return prev + diff * 0.1;
      });
    }, 30);
    return () => clearInterval(interval);
  }, [boss.currentHp]);

  // Floating Text Animation Loop
  useEffect(() => {
    const interval = setInterval(() => {
      setFloatingTexts((prev) =>
        prev.map((ft) => ({ ...ft, y: ft.y - 2 })).filter((ft) => ft.y > -50),
      );
    }, 30);
    return () => clearInterval(interval);
  }, []);

  const hpPct = (hpAnim / boss.totalHp) * 100;

  const spawnFloatingText = (text: string, color: string = "white") => {
    // Random offset
    const xOffset = Math.random() * 100 - 50;
    const yOffset = Math.random() * 50 - 25;

    const newText: FloatingText = {
      id: Date.now() + Math.random(),
      text,
      x: xOffset,
      y: yOffset,
      color,
    };
    setFloatingTexts((prev) => [...prev, newText]);
  };

  const handleSendMessage = async () => {
    if (!input.trim()) return;
    const msgToSend = input;
    setInput("");

    try {
      await sendChatAction(msgToSend);
    } catch {
      // console.error("Failed to send message", _e);
    }
  };

  const handleAttack = async (_e: React.MouseEvent) => {
    if (!boss.id) return;

    // 1. Check Energy (Optimistic Check)
    if (kineticEnergy < ATTACK_COST) {
      spawnFloatingText("LOW ENERGY!", "#ef4444"); // Red
      return;
    }

    // 2. Consume Energy Optimistically
    setKineticEnergy((prev) => Math.max(0, prev - ATTACK_COST));

    // 3. Visual Juice
    setShake(true);
    setTimeout(() => setShake(false), 200);

    // 4. Server Action
    try {
      const result = await attackBossAction(boss.id);
      if (result.damage) {
        spawnFloatingText(`-${result.damage}`, "#facc15"); // Yellow
      }
    } catch (err: any) {
      console.error("Attack failed", err);
      // Revert Energy on fail? Or just let it sync next time.
      spawnFloatingText("MISS!", "#a1a1aa");
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -20 }}
      className={cn(
        "h-full bg-forge-900 overflow-hidden flex flex-col font-serif transition-transform duration-75",
        shake ? "translate-x-1 translate-y-1" : "",
      )}
    >
      {/* Header */}
      <div className="bg-black/50 border-b border-forge-border p-6 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-red-950/30 border border-red-500/50 rounded-lg shadow-[0_0_15px_rgba(239,68,68,0.2)]">
            <Swords className="w-8 h-8 text-red-500" />
          </div>
          <div>
            <h1 className="text-3xl font-black text-white uppercase tracking-tighter">
              The Guild Hall
            </h1>
            <div className="flex items-center gap-4 text-xs font-bold uppercase tracking-widest text-zinc-500">
              <span className="flex items-center gap-1">
                {isConnected ? (
                  <Users className="w-3 h-3 text-cyan-500" />
                ) : (
                  <WifiOff className="w-3 h-3 text-red-500" />
                )}
                {isConnected ? `${onlineCount} Online` : "Offline Mode"}
              </span>
              <span className="flex items-center gap-1 text-yellow-500">
                <Zap className="w-3 h-3 text-yellow-500" /> {kineticEnergy}{" "}
                Energy
                <span className="opacity-50 text-[10px] ml-1">
                  (Cost: {ATTACK_COST})
                </span>
              </span>
            </div>
          </div>
        </div>
        <button
          onClick={onClose}
          className="bg-red-900/20 border-2 border-red-500/50 hover:bg-red-900/50 text-red-500 px-6 py-2 rounded-lg font-bold uppercase text-xs transition-all hover:scale-105 active:scale-95 flex items-center gap-2 shadow-[0_0_15px_rgba(239,68,68,0.2)]"
        >
          <DoorOpen className="w-4 h-4" />
          Retreat
        </button>
      </div>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Battle Area */}
        <div className="flex-1 p-8 flex flex-col items-center justify-center relative overflow-hidden bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-red-900/10 via-forge-900 to-forge-900">
          {/* Floating Texts Layer */}
          <div className="absolute inset-0 pointer-events-none flex items-center justify-center overflow-visible">
            {floatingTexts.map((ft) => (
              <div
                key={ft.id}
                className="absolute text-4xl font-black animate-float-up"
                style={{
                  transform: `translate(${ft.x}px, ${ft.y}px)`,
                  color: ft.color,
                  textShadow: "0 2px 4px rgba(0,0,0,0.8)",
                }}
              >
                {ft.text}
              </div>
            ))}
          </div>

          {/* Boss Visualization */}
          <div
            className={cn(
              "relative group cursor-pointer transition-transform active:scale-95 select-none",
              kineticEnergy < ATTACK_COST
                ? "opacity-50 cursor-not-allowed filter grayscale"
                : "",
            )}
            onClick={handleAttack}
          >
            <motion.div
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.9, filter: "brightness(1.5)" }}
              className="text-[12rem] drop-shadow-[0_0_50px_rgba(239,68,68,0.3)] filter grayscale-[0.2] relative z-10"
            >
              {boss.image}
            </motion.div>
            <div className="absolute -bottom-4 left-1/2 -translate-x-1/2 whitespace-nowrap bg-black/80 border border-red-500/50 px-4 py-1 rounded-full pointer-events-none">
              <span className="text-red-500 font-black tracking-[0.2em] uppercase text-sm">
                {boss.name}
              </span>
            </div>
            {/* Tooltip for Attack */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none flex flex-col items-center gap-1">
              {kineticEnergy >= ATTACK_COST ? (
                <>
                  <span className="text-4xl font-black text-red-500 text-shadow-neon stroke-black whitespace-nowrap">
                    CLICK TO ATTACK
                  </span>
                  <span className="text-xs font-bold text-yellow-500 bg-black/80 px-2 py-1 rounded uppercase">
                    Costs {ATTACK_COST} Energy
                  </span>
                </>
              ) : (
                <span className="text-2xl font-black text-zinc-500 text-shadow-neon stroke-black whitespace-nowrap">
                  NEED ENERGY
                </span>
              )}
            </div>
          </div>

          {/* Boss HP Bar */}
          <div className="w-full max-w-2xl mt-16 space-y-2">
            <div className="flex justify-between items-end">
              <div className="flex flex-col">
                <span className="text-[10px] uppercase font-black text-zinc-500 tracking-widest">
                  Global Integrity
                </span>
                <span className="text-2xl font-black text-red-500 font-mono tracking-tighter italic">
                  {Math.round(hpAnim).toLocaleString()}{" "}
                  <span className="text-zinc-600 text-sm italic">
                    / {boss.totalHp.toLocaleString()} HP
                  </span>
                </span>
              </div>
              <span className="text-4xl font-black text-white italic opacity-20">
                {Math.floor(hpPct)}%
              </span>
            </div>
            <div className="h-4 w-full bg-zinc-950 rounded-full border-2 border-zinc-900 p-0.5 overflow-hidden shadow-inner">
              <div
                className="h-full bg-gradient-to-r from-red-900 via-red-600 to-red-400 rounded-full shadow-[0_0_20px_rgba(239,68,68,0.6)] transition-all duration-100 ease-out relative overflow-hidden"
                style={{ width: `${hpPct}%` }}
              >
                <div className="absolute inset-0 bg-[linear-gradient(45deg,rgba(255,255,255,0.2)_25%,transparent_25%,transparent_50%,rgba(255,255,255,0.2)_50%,rgba(255,255,255,0.2)_75%,transparent_75%,transparent)] bg-[length:2rem_2rem] animate-scroll"></div>
              </div>
            </div>
          </div>

          {/* Boss Info Card */}
          <div className="mt-12 grid grid-cols-2 gap-6 w-full max-w-2xl">
            <div className="bg-black/40 border border-zinc-800 p-4 rounded-lg">
              <h3 className="text-xs font-black text-zinc-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                <Info className="w-3 h-3 text-cyan-500" /> Intelligence
              </h3>
              <p className="text-xs text-zinc-300 leading-relaxed italic">
                &quot;{boss.description}&quot;
              </p>
            </div>
            <div className="bg-black/40 border border-zinc-800 p-4 rounded-lg">
              <h3 className="text-xs font-black text-zinc-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                <Shield className="w-3 h-3 text-red-500" /> Bounties
              </h3>
              <div className="flex flex-wrap gap-2">
                {boss.rewards.map((reward, i) => (
                  <span
                    key={i}
                    className="text-[9px] font-bold text-rarity-legendary bg-rarity-legendary/10 border border-rarity-legendary/30 px-2 py-0.5 rounded uppercase"
                  >
                    {reward}
                  </span>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Sidebar - Raid Chat/Log */}
        <div className="w-96 bg-black/40 border-l border-forge-border flex flex-col">
          <div className="p-4 border-b border-forge-border bg-black/20">
            <h2 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
              <Users className="w-4 h-4 text-cyan-500" /> Raid Comms
            </h2>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 font-sans no-scrollbar flex flex-col-reverse">
            {[...messages].reverse().map((msg) => (
              <div
                key={msg.id}
                className={cn(
                  "p-3 rounded-lg border text-xs leading-relaxed animate-slide-in",
                  msg.type === "LOG"
                    ? "bg-red-950/20 border-red-500/20 text-red-400 italic font-medium"
                    : "bg-zinc-900/50 border-zinc-800 text-zinc-300",
                )}
              >
                <div className="flex justify-between items-center mb-1">
                  <span
                    className={cn(
                      "font-black uppercase tracking-tighter",
                      msg.userName === "Titan"
                        ? "text-cyan-500"
                        : "text-zinc-500",
                    )}
                  >
                    {msg.userName}
                  </span>
                  <span className="text-[9px] opacity-30">
                    {new Date(msg.timestamp).toLocaleTimeString([], {
                      hour: "2-digit",
                      minute: "2-digit",
                    })}
                  </span>
                </div>
                <p>{msg.message}</p>
              </div>
            ))}
          </div>

          {/* Chat Input */}
          <div className="p-4 border-t border-forge-border bg-black/40">
            <div className="relative group">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyPress={(e) => e.key === "Enter" && handleSendMessage()}
                placeholder={
                  isConnected
                    ? "Coordinate attack..."
                    : "Connecting to Neural Link..."
                }
                disabled={!isConnected}
                className="w-full bg-forge-800 border border-forge-border rounded-lg py-2 pl-4 pr-12 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-cyan-500 transition-colors disabled:opacity-50"
              />
              <button
                onClick={handleSendMessage}
                disabled={!isConnected}
                className="absolute right-2 top-1/2 -translate-y-1/2 p-2 text-zinc-500 hover:text-cyan-500 transition-colors disabled:opacity-50"
              >
                <Send className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>
      </div>
    </motion.div>
  );
};

export default GuildHall;

import React, {
  useState,
  useEffect,
  useCallback,
  useRef,
  useContext,
  memo,
} from "react";
import {
  Block,
  Set as WorkoutSet,
  ExerciseLogic,
  IntervalsWellness,
  AppSettings,
  Exercise,
} from "@/types";
import {
  Check,
  Info,
  X,
  Lock,
  Zap,
  Sword,
  Shield,
  Crown,
  LogOut,
  Flame,
  Battery,
  Mic,
  Camera,
  Waves,
  ArrowUp,
  ArrowDown,
  Timer,
  Plus,
  Copy,
  Ban,
} from "lucide-react";
import {
  roundToPlates,
  fireConfetti,
  calculateRarity,
  playSound,
  calculateTitanRank,
} from "@/utils";
import { calculateApre, ApreSuggestion } from "@/utils/apre";
import PlateVisualizer from "@/features/strength/components/PlateVisualizer";
import ExerciseLibrary from "@/features/strength/components/ExerciseLibrary";
import HeartRateMonitor from "@/features/bio/components/HeartRateMonitor";
import VisionRepCounter from "@/features/training/components/VisionRepCounter";
import { AchievementContext } from "@/context/AchievementContext";
import { useSkills } from "@/context/SkillContext";
import { IoTService } from "@/services/iot";
import { RaidService } from "@/services/raid";
import { NeuroService } from "@/services/neuro";
import { StorageService } from "@/services/storage";
import { useVoiceCommand } from "@/hooks/useVoiceCommand";

interface ActionViewProps {
  block: Block;
  onComplete: () => void;
  onAbort: () => void;
  bpm: number | null;
  isBtConnected: boolean;
  onBtConnect: () => void;
  onBtSimulate: () => void;
  btError?: string | null;
  wellness: IntervalsWellness | null;
  previousStats?: Record<
    string,
    { weight: number; reps: number; e1rm: number }
  >;
  onSessionUpdate?: (exercises: Exercise[]) => void; // Persistence Callback
}

interface SetRowProps {
  set: WorkoutSet;
  exIndex: number;
  setIndex: number;
  isFocused: boolean;
  isLocked: boolean;
  displayWeight: number;
  isLandmine: boolean;
  rarity: string;
  onToggle: (exIdx: number, setIdx: number) => void;
  onRepsChange: (exIdx: number, setIdx: number, newReps: number) => void;
  onWeightChange: (exIdx: number, setIdx: number, newWeight: number) => void;
  onRpeChange: (exIdx: number, setIdx: number, newRpe: number) => void;
  activeSetRef: React.RefObject<HTMLDivElement | null> | null;
  previous?: { weight: number; reps: number; e1rm: number };
}

const SetRow = memo(
  ({
    set,
    exIndex,
    setIndex,
    isFocused,
    isLocked,
    displayWeight,
    isLandmine,
    rarity,
    onToggle,
    onRepsChange,
    onWeightChange,
    onRpeChange,
    activeSetRef,
    previous,
  }: SetRowProps) => {
    const getRarityBorder = (rarity: string) => {
      switch (rarity) {
        case "poor":
          return "border-rarity-poor shadow-none opacity-50";
        case "common":
          return "border-rarity-common/50 shadow-none";
        case "uncommon":
          return "border-rarity-uncommon shadow-[0_0_10px_rgba(30,255,0,0.1)]";
        case "rare":
          return "border-rarity-rare shadow-[0_0_15px_rgba(0,112,221,0.2)]";
        case "epic":
          return "border-rarity-epic shadow-[0_0_20px_rgba(163,53,238,0.3)]";
        case "legendary":
          return "border-rarity-legendary shadow-[0_0_25px_rgba(255,128,0,0.4)]";
        default:
          return "border-zinc-800";
      }
    };

    const getRarityText = (rarity: string) => {
      switch (rarity) {
        case "poor":
          return "text-rarity-poor";
        case "common":
          return "text-rarity-common";
        case "uncommon":
          return "text-rarity-uncommon";
        case "rare":
          return "text-rarity-rare";
        case "epic":
          return "text-rarity-epic";
        case "legendary":
          return "text-rarity-legendary";
        default:
          return "text-zinc-500";
      }
    };

    const borderColor = getRarityBorder(rarity);
    const textColor = getRarityText(rarity);
    const isAmrap = typeof set.reps === "string";
    const inputValue =
      set.completedReps !== undefined
        ? set.completedReps
        : isAmrap
          ? ""
          : set.reps;

    // --- COMPACT VIEW (Completed Sets) ---
    if (set.completed) {
      return (
        <div
          className={`flex items-center justify-between p-2 bg-zinc-950/50 border border-zinc-900 rounded-md opacity-70 transition-all hover:opacity-100 cursor-pointer`}
          onClick={() => onToggle(exIndex, setIndex)}
        >
          <div className="flex items-center gap-3">
            <div className="bg-green-900/30 p-1 rounded-full border border-green-900">
              <Check className="w-3 h-3 text-green-500" />
            </div>
            <div className="flex flex-col">
              <span className="text-xs font-bold text-zinc-500 uppercase tracking-wider">
                Set {setIndex + 1}
              </span>
              <div className="flex items-center gap-2 text-sm font-mono text-zinc-300">
                <span className="font-bold text-white">
                  {set.completedReps}
                </span>{" "}
                reps
                <span className="text-zinc-600">@</span>
                <span>{displayWeight > 0 ? `${displayWeight}kg` : "BW"}</span>
              </div>
            </div>
          </div>
          {set.rarity && set.rarity !== "common" && (
            <span
              className={`text-[9px] uppercase font-bold px-2 py-0.5 border rounded-full ${getRarityText(set.rarity)} border-current opacity-60`}
            >
              {set.rarity}
            </span>
          )}
        </div>
      );
    }

    // --- EXPANDED VIEW (Active/Pending) ---
    return (
      <div
        ref={activeSetRef}
        className={`group relative bg-[#0a0a0a] border-2 rounded-lg overflow-hidden transition-all duration-300 
              ${isFocused ? `scale-[1.02] z-10 shadow-xl ${borderColor}` : `border-zinc-900 hover:border-zinc-700`}
            `}
      >
        <div className={`flex flex-col gap-3 ${isFocused ? "p-6" : "p-4"}`}>
          {/* Header Row */}
          <div className="flex justify-between items-start">
            <div className="flex flex-col">
              <div className="flex items-center gap-2 mb-1">
                <span
                  className={`text-xs font-serif uppercase font-bold ${isFocused ? "text-zinc-300" : "text-zinc-600"}`}
                >
                  Objective {setIndex + 1}
                </span>
                {rarity === "epic" && !set.completed && (
                  <span className="text-[10px] font-bold px-1.5 py-0.5 rounded uppercase tracking-wider text-rarity-epic border border-rarity-epic/30 bg-rarity-epic/10 animate-pulse">
                    Epic Loot
                  </span>
                )}
              </div>

              {/* Stats Row */}
              <div className="flex flex-col gap-2 mt-2">
                {/* Previous Params Ghost */}
                {isFocused && previous && previous.e1rm > 0 && (
                  <div className="text-[10px] text-zinc-500 font-mono flex items-center gap-2 mb-1">
                    <span className="uppercase tracking-widest text-zinc-600">
                      Last:
                    </span>
                    {previous.weight > 0 ? (
                      <>
                        <span>
                          {previous.weight}kg x {previous.reps}
                        </span>
                        <span className="text-zinc-700">|</span>
                      </>
                    ) : null}
                    <span>e1RM: {previous.e1rm}</span>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        if (previous.weight > 0)
                          onWeightChange(exIndex, setIndex, previous.weight);
                        if (previous.reps > 0)
                          onRepsChange(exIndex, setIndex, previous.reps);
                        playSound("ding");
                      }}
                      className="ml-2 p-0.5 hover:bg-zinc-800 rounded text-zinc-600 hover:text-indigo-400 transition-colors"
                      title="Copy Last Set"
                    >
                      <Copy className="w-3 h-3" />
                    </button>
                  </div>
                )}

                <div className="flex items-end gap-4">
                  {/* REPS INPUT */}
                  <div className="flex flex-col items-center">
                    {isFocused ? (
                      <>
                        <div className="flex items-center gap-2">
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              onRepsChange(
                                exIndex,
                                setIndex,
                                Math.max(
                                  0,
                                  (set.completedReps ||
                                    (typeof set.reps === "number"
                                      ? set.reps
                                      : 0) ||
                                    0) - 1,
                                ),
                              );
                            }}
                            className="w-8 h-8 rounded-full bg-zinc-800 text-zinc-400 hover:bg-zinc-700 flex items-center justify-center font-bold"
                          >
                            -
                          </button>
                          <input
                            type="number"
                            value={inputValue}
                            placeholder={isAmrap ? "MAX" : String(set.reps)}
                            onChange={(e) =>
                              onRepsChange(
                                exIndex,
                                setIndex,
                                parseInt(e.target.value) || 0,
                              )
                            }
                            onClick={(e) => e.stopPropagation()}
                            className="w-16 bg-zinc-900 border-b-2 border-zinc-500 text-white text-3xl font-serif font-bold text-center p-0 rounded-none focus:border-[#c79c6e] focus:outline-none placeholder-zinc-700"
                          />
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              onRepsChange(
                                exIndex,
                                setIndex,
                                (set.completedReps ||
                                  (typeof set.reps === "number"
                                    ? set.reps
                                    : 0) ||
                                  0) + 1,
                              );
                            }}
                            className="w-8 h-8 rounded-full bg-zinc-800 text-zinc-400 hover:bg-zinc-700 flex items-center justify-center font-bold"
                          >
                            +
                          </button>
                        </div>
                        <span className="text-zinc-500 text-[9px] uppercase font-bold tracking-widest mt-1">
                          Reps
                        </span>
                      </>
                    ) : (
                      <div className="flex items-baseline gap-1">
                        <span className="text-2xl font-serif font-bold text-white">
                          {isAmrap ? "AMRAP" : set.reps}
                        </span>
                        <span className="text-zinc-600 text-xs font-bold uppercase">
                          reps
                        </span>
                      </div>
                    )}
                  </div>

                  {/* WEIGHT INPUT */}
                  <div className="flex flex-col items-center">
                    {isFocused ? (
                      <>
                        <div className="flex items-center gap-2">
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              onWeightChange(
                                exIndex,
                                setIndex,
                                Math.max(0, displayWeight - 2.5),
                              );
                            }}
                            className="w-8 h-8 rounded-full bg-zinc-800 text-zinc-400 hover:bg-zinc-700 flex items-center justify-center font-bold"
                          >
                            -
                          </button>
                          <input
                            type="number"
                            value={displayWeight}
                            onChange={(e) =>
                              onWeightChange(
                                exIndex,
                                setIndex,
                                parseFloat(e.target.value) || 0,
                              )
                            }
                            onClick={(e) => e.stopPropagation()}
                            className="w-20 bg-zinc-900 border-b-2 border-zinc-500 text-white text-3xl font-serif font-bold text-center p-0 rounded-none focus:border-blue-500 focus:outline-none"
                          />
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              onWeightChange(
                                exIndex,
                                setIndex,
                                displayWeight + 2.5,
                              );
                            }}
                            className="w-8 h-8 rounded-full bg-zinc-800 text-zinc-400 hover:bg-zinc-700 flex items-center justify-center font-bold"
                          >
                            +
                          </button>
                        </div>
                        <span className="text-zinc-500 text-[9px] uppercase font-bold tracking-widest mt-1">
                          KG Load
                        </span>
                      </>
                    ) : (
                      <div className="flex flex-col items-center ml-2">
                        <span
                          className={`font-mono font-bold ${isFocused ? "text-2xl" : "text-lg"} ${textColor}`}
                        >
                          {displayWeight > 0 ? `${displayWeight}` : "BW"}
                        </span>
                        <span className="text-zinc-600 text-[10px] uppercase font-bold tracking-widest">
                          Weight
                        </span>
                      </div>
                    )}
                  </div>

                  {/* RPE INPUT (Only when focused) */}
                  {isFocused && (
                    <div className="flex flex-col items-center ml-2 animate-fade-in-left">
                      <div className="bg-zinc-900 p-1 rounded-lg border border-zinc-800 flex flex-col items-center">
                        <input
                          type="number"
                          max={10}
                          min={1}
                          step={0.5}
                          value={set.rpe || ""}
                          placeholder="-"
                          onChange={(e) =>
                            onRpeChange(
                              exIndex,
                              setIndex,
                              parseFloat(e.target.value),
                            )
                          }
                          onClick={(e) => e.stopPropagation()}
                          className="w-10 bg-transparent text-center text-yellow-500 font-bold text-xl focus:outline-none"
                        />
                        <span className="text-[8px] text-zinc-500 uppercase font-bold">
                          RPE
                        </span>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* Action Button */}
            <button
              onClick={() => onToggle(exIndex, setIndex)}
              disabled={isLocked}
              className={`rounded-xl flex items-center justify-center transition-all shadow-lg active:scale-95
                          ${isLocked
                  ? "bg-red-950/10 border-2 border-red-900/50 text-red-900 cursor-not-allowed h-12 w-12"
                  : isFocused
                    ? "bg-zinc-100 text-black h-16 w-16 hover:bg-white hover:scale-105 shadow-[0_0_20px_rgba(255,255,255,0.1)]" // Giant button for active
                    : "bg-zinc-900 border border-zinc-700 text-zinc-500 h-12 w-12 hover:border-zinc-500 hover:text-zinc-300"
                }`}
            >
              {isLocked ? (
                <Lock className="w-5 h-5 animate-pulse" />
              ) : (
                <Shield
                  className={`${isFocused ? "w-8 h-8 fill-current" : "w-5 h-5"}`}
                />
              )}
            </button>
          </div>

          {/* Footer / Visualizer */}
          <div className="mt-1">
            {displayWeight > 20 &&
              !isLocked &&
              (isFocused || !set.completed) && (
                <PlateVisualizer
                  weight={displayWeight}
                  isSingleLoaded={isLandmine}
                />
              )}
            {isLocked && (
              <div className="mt-2 p-2 bg-red-950/30 border border-red-900/50 rounded flex items-center gap-2">
                <Ban className="w-4 h-4 text-red-500 animate-pulse" />
                <span className="text-xs font-bold text-red-400 uppercase tracking-widest">
                  Aggro High: Recover HR
                </span>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  },
  (prev, next) => {
    return (
      prev.set.completed === next.set.completed &&
      prev.set.completedReps === next.set.completedReps &&
      prev.set.rarity === next.set.rarity &&
      prev.isFocused === next.isFocused &&
      prev.isLocked === next.isLocked &&
      prev.displayWeight === next.displayWeight &&
      prev.set.rpe === next.set.rpe &&
      prev.previous === next.previous
    );
  },
);

SetRow.displayName = "SetRow";

const ActionView: React.FC<ActionViewProps> = ({
  block,
  onComplete,
  onAbort,
  bpm,
  isBtConnected,
  onBtConnect,
  onBtSimulate,
  btError,
  wellness,
  previousStats = {},
  onSessionUpdate,
}) => {
  const [exercises, setExercises] = useState(block.exercises || []);
  const [openInfoId, setOpenInfoId] = useState<string | null>(null);
  const [showVision, setShowVision] = useState(false);
  const [cursor, setCursor] = useState<[number, number]>([0, 0]);
  const [criticalHit, setCriticalHit] = useState<{
    show: boolean;
    msg: string;
  }>({ show: false, msg: "" });
  const [apreSuggestion, setApreSuggestion] = useState<ApreSuggestion | null>(
    null,
  );

  // Game State
  const [mana, setMana] = useState(wellness?.bodyBattery || 50);
  const maxMana = 100;
  const [manaDrain, setManaDrain] = useState<{ show: boolean; amount: number }>(
    { show: false, amount: 0 },
  );
  const [isNeuroActive, setIsNeuroActive] = useState(false);

  // REST TIMER STATE
  const [restTimer, setRestTimer] = useState(0);
  const [isResting, setIsResting] = useState(false);

  const achievementContext = useContext(AchievementContext);
  const { purchasedSkillIds } = useSkills();
  const unlockedIds = achievementContext?.unlockedIds || new Set();
  const { isElite } = calculateTitanRank(unlockedIds);
  const hasPrimalRoar = purchasedSkillIds.has("beast_1");

  // --- NEURO LINK LOGIC ---
  useEffect(() => {
    if (isNeuroActive) {
      if (bpm && bpm < 120) NeuroService.engageRecovery();
      else NeuroService.engageFocus();
    } else {
      NeuroService.stop();
    }
    return () => NeuroService.stop();
  }, [isNeuroActive, bpm]);

  // --- PERSISTENCE: Propagate state up whenever it changes ---
  useEffect(() => {
    if (onSessionUpdate) {
      onSessionUpdate(exercises);
    }
  }, [exercises, onSessionUpdate]);

  // --- REST TIMER LOGIC ---
  useEffect(() => {
    let interval: any;
    if (isResting) {
      interval = setInterval(() => {
        setRestTimer((prev) => prev + 1);
      }, 1000);
    } else {
      setRestTimer(0);
    }
    return () => clearInterval(interval);
  }, [isResting]);

  const handleSkipRest = () => {
    setIsResting(false);
    setRestTimer(0);
  };

  const [heroName, setHeroName] = useState("Titan");
  useEffect(() => {
    IoTService.init();
    StorageService.getState<AppSettings>("settings").then((s) => {
      if (s?.heroName) setHeroName(s.heroName);
    });
  }, []);

  // Initial Cursor Position - Find first incomplete
  useEffect(() => {
    let found = false;
    for (let i = 0; i < exercises.length; i++) {
      for (let j = 0; j < exercises[i].sets.length; j++) {
        if (!exercises[i].sets[j].completed) {
          setCursor([i, j]);
          found = true;
          break;
        }
      }
      if (found) break;
    }
     
  }, []); // Only on mount

  useEffect(() => {
    if (!isBtConnected) return;
    if (bpm && bpm > 160) IoTService.triggerRedAlert();
    else if (bpm && bpm < 120) IoTService.triggerRecovery();
    else IoTService.triggerFocus();
  }, [bpm, isBtConnected]);

  useEffect(() => {
    if (criticalHit.show) {
      const t = setTimeout(
        () => setCriticalHit({ show: false, msg: "" }),
        2000,
      );
      return () => clearTimeout(t);
    }
  }, [criticalHit.show]);

  useEffect(() => {
    if (manaDrain.show) {
      const t = setTimeout(
        () => setManaDrain({ show: false, amount: 0 }),
        1000,
      );
      return () => clearTimeout(t);
    }
  }, [manaDrain.show]);

  const activeSetRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (activeSetRef.current)
      activeSetRef.current.scrollIntoView({
        behavior: "smooth",
        block: "center",
      });
  }, [cursor]);

  const isSystemOverheated = bpm !== null && bpm > 120;
  const isBlockComplete = exercises.every((ex) =>
    ex.sets.every((s) => s.completed),
  );
  const isManaEmpty = mana <= 0;

  const handleRepsChange = useCallback(
    (exIndex: number, setIndex: number, newReps: number) => {
      setExercises((prev) => {
        const newExercises = [...prev];
        const newSet = { ...newExercises[exIndex].sets[setIndex] };
        newSet.completedReps = newReps;
        newExercises[exIndex].sets[setIndex] = newSet;
        return newExercises;
      });
    },
    [],
  );

  const handleWeightChange = useCallback(
    (exIndex: number, setIndex: number, newWeight: number) => {
      setExercises((prev) => {
        const newExercises = [...prev];
        const newSet = { ...newExercises[exIndex].sets[setIndex] };
        newSet.weight = newWeight;
        // Also update percent if applicable, relative to TM? simpler to just set absolute weight for now
        // If it was logic based, we might break the logic link, but user override is king.
        newExercises[exIndex].sets[setIndex] = newSet;
        return newExercises;
      });
    },
    [],
  );

  const handleRpeChange = useCallback(
    (exIndex: number, setIndex: number, newRpe: number) => {
      setExercises((prev) => {
        const newExercises = [...prev];
        const newSet = { ...newExercises[exIndex].sets[setIndex] };
        newSet.rpe = newRpe;
        newExercises[exIndex].sets[setIndex] = newSet;
        return newExercises;
      });
    },
    [],
  );

  const handleToggleSet = useCallback(
    (exIndex: number, setIndex: number) => {
      setExercises((prev) => {
        const newExercises = [...prev];
        const exercise = newExercises[exIndex];
        const newSet = { ...exercise.sets[setIndex] };

        let weight = newSet.weight || 0;
        if (
          exercise.logic === ExerciseLogic.TM_PERCENT &&
          exercise.trainingMax &&
          newSet.weightPct
        ) {
          weight = roundToPlates(exercise.trainingMax * newSet.weightPct);
        }

        if (!newSet.completed && isSystemOverheated) {
          playSound("fail");
          return prev;
        }

        if (!newSet.completed) {
          // MARKING AS COMPLETE
          if (
            newSet.completedReps === undefined ||
            newSet.completedReps === 0
          ) {
            if (typeof newSet.reps === "number")
              newSet.completedReps = newSet.reps;
          }
          newSet.rarity = calculateRarity(newSet, exercise.logic);

          // Trigger Rest Timer
          setIsResting(true);

          // --- APRE LOGIC ---
          if (setIndex < exercise.sets.length - 1) {
            const nextSet = exercise.sets[setIndex + 1];
            if (
              exercise.logic === ExerciseLogic.TM_PERCENT &&
              exercise.trainingMax &&
              nextSet.weightPct
            ) {
              const currentSetWeight = weight;
              const rpe = 8;
              const suggestion = calculateApre(
                currentSetWeight,
                newSet.completedReps || 0,
                rpe,
              );
              if (suggestion) setApreSuggestion(suggestion);
            }
          }
        } else {
          // UN-COMPLETING
          setIsResting(false);
          setRestTimer(0);
        }

        newSet.completed = !newSet.completed;
        newExercises[exIndex].sets[setIndex] = newSet;

        if (newSet.completed) {
          let cost = 5;
          if (newSet.weightPct && newSet.weightPct > 0.8) cost = 10;
          if (typeof newSet.reps === "string") cost = 15;
          setMana((m) => Math.max(0, m - cost));
          setManaDrain({ show: true, amount: cost });

          const damage = Math.floor(weight * (newSet.completedReps || 1));
          RaidService.broadcastDamage(heroName, damage, exercise.name);

          if (newSet.isPrZone) IoTService.triggerRedAlert();
          else IoTService.triggerVictory();

          if (exercise.id === "ex_belt_squat" && weight >= 140)
            achievementContext?.unlockAchievement("deep_squat_dynasty");
          if (exercise.id === "ex_landmine_press" && weight >= 100)
            achievementContext?.unlockAchievement("perfect_plates");

          if (
            newSet.rarity === "legendary" ||
            newSet.rarity === "epic" ||
            newSet.rarity === "rare"
          ) {
            if (
              typeof newSet.reps === "string" ||
              (newSet.completedReps &&
                newSet.reps &&
                newSet.completedReps > newSet.reps)
            ) {
              setCriticalHit({
                show: true,
                msg: `${newSet.rarity.toUpperCase()} Performance!`,
              });
              playSound("loot_epic");
              fireConfetti();
            } else playSound("ding");
          } else playSound("ding");
        }
        return newExercises;
      });

      // Auto-advance cursor if completing
      const currentSetStatus = exercises[exIndex].sets[setIndex].completed;
      // Logic note: we are using stale state 'exercises' here, but it's OK for logic direction
      if (!currentSetStatus) {
        if (setIndex < exercises[exIndex].sets.length - 1)
          setCursor([exIndex, setIndex + 1]);
        else if (exIndex < exercises.length - 1) setCursor([exIndex + 1, 0]);
      }
    },
    [isSystemOverheated, achievementContext, heroName, exercises],
  );

  // --- VISION ---
  const handleVisionRep = useCallback(() => {
    const [exIndex, setIndex] = cursor;
    const currentSet = exercises[exIndex].sets[setIndex];
    const currentReps = currentSet.completedReps || 0;
    handleRepsChange(exIndex, setIndex, currentReps + 1);
    playSound("ding");
  }, [cursor, exercises, handleRepsChange]);

  // --- VOICE ---
  const handleVoiceCommand = useCallback(
    (type: string, value: number | string) => {
      const [exIndex, setIndex] = cursor;
      if (type === "REPS") handleRepsChange(exIndex, setIndex, value as number);
      else if (type === "COMPLETE") handleToggleSet(exIndex, setIndex);
    },
    [cursor, handleRepsChange, handleToggleSet],
  );

  const { isListening, toggleListening, lastCommand } =
    useVoiceCommand(handleVoiceCommand);

  const handleApplyApre = () => {
    if (!apreSuggestion) return;
    const [exIdx, setIdx] = cursor;

    setExercises((prev) => {
      const next = [...prev];
      const ex = next[exIdx];
      const nextSetIdx = ex.sets.findIndex(
        (s, i) => !s.completed && i > setIdx,
      ); // Find next active

      if (nextSetIdx !== -1) {
        const newWeight = apreSuggestion.newWeight;
        if (ex.trainingMax) {
          ex.sets[nextSetIdx].weightPct = newWeight / ex.trainingMax;
          ex.sets[nextSetIdx].weight = newWeight;
        }
      }
      return next;
    });
    setApreSuggestion(null);
    playSound("quest_accept");
  };

  const stateRef = useRef({
    exercises,
    cursor,
    isSystemOverheated,
    isBlockComplete,
    isManaEmpty,
  });
  useEffect(() => {
    stateRef.current = {
      exercises,
      cursor,
      isSystemOverheated,
      isBlockComplete,
      isManaEmpty,
    };
  }, [exercises, cursor, isSystemOverheated, isBlockComplete, isManaEmpty]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement) return;
      const {
        exercises: currExercises,
        cursor: currCursor,
        isSystemOverheated: currOverheated,
        isBlockComplete: currComplete,
        isManaEmpty: currManaEmpty,
      } = stateRef.current;
      const [exIdx, setIdx] = currCursor;

      if (e.code === "ArrowDown" || e.code === "KeyS") {
        e.preventDefault();
        if (setIdx < currExercises[exIdx].sets.length - 1)
          setCursor([exIdx, setIdx + 1]);
        else if (exIdx < currExercises.length - 1) setCursor([exIdx + 1, 0]);
      } else if (e.code === "ArrowUp" || e.code === "KeyW") {
        e.preventDefault();
        if (setIdx > 0) setCursor([exIdx, setIdx - 1]);
        else if (exIdx > 0)
          setCursor([exIdx - 1, currExercises[exIdx - 1].sets.length - 1]);
      } else if (
        e.code === "Space" ||
        e.code === "Enter" ||
        e.code === "ArrowRight" ||
        e.code === "KeyD"
      ) {
        e.preventDefault();
        if (
          e.code === "Enter" &&
          currComplete &&
          !currOverheated &&
          !currManaEmpty
        ) {
          playSound("ding");
          onComplete();
          return;
        }
        handleToggleSet(exIdx, setIdx);
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [handleToggleSet, onComplete]);

  const manaPct = (mana / maxMana) * 100;
  let manaColor = "bg-blue-500";
  if (manaPct < 30) manaColor = "bg-orange-500";
  if (manaPct < 10) manaColor = "bg-red-600 animate-pulse";
  const isRested = (wellness?.sleepScore || 0) > 80;

  const formatTime = (secs: number) => {
    const m = Math.floor(secs / 60);
    const s = secs % 60;
    return `${m}:${s.toString().padStart(2, "0")}`;
  };

  return (
    <div
      className={`flex flex-col h-full bg-[#050505] transition-colors duration-500 relative ${!isSystemOverheated && bpm ? "bg-green-950/5" : ""}`}
    >
      {/* REST TIMER HUD */}
      {isResting && (
        <div className="fixed top-24 right-4 z-50 animate-slide-left">
          <div className="bg-[#111] border-2 border-zinc-700 rounded-lg p-3 shadow-[0_0_20px_rgba(0,0,0,0.8)] flex items-center gap-4">
            <div className="text-center">
              <div className="text-[10px] uppercase font-bold text-zinc-500 mb-1">
                Rest Timer
              </div>
              <div className="text-2xl font-mono font-bold text-white flex items-center gap-2">
                <Timer className="w-5 h-5 text-zinc-400" />
                {formatTime(restTimer)}
              </div>
            </div>
            <button
              onClick={handleSkipRest}
              className="bg-zinc-800 hover:bg-zinc-700 text-white px-3 py-2 rounded text-xs font-bold uppercase"
            >
              Ready
            </button>
          </div>
        </div>
      )}

      {/* APRE TOAST */}
      {apreSuggestion && (
        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 z-50 animate-slide-up w-80">
          <div className="bg-[#111] border-2 border-cyan-500 rounded-lg p-4 shadow-[0_0_20px_rgba(6,182,212,0.3)]">
            <div className="flex items-center gap-2 mb-2 text-cyan-400 font-bold uppercase text-xs tracking-widest">
              <Zap className="w-4 h-4" /> Neuro-Optimization
            </div>
            <p className="text-zinc-300 text-xs mb-3">
              {apreSuggestion.reason}
            </p>
            <div className="flex gap-2">
              <button
                onClick={handleApplyApre}
                className="flex-1 bg-cyan-900/50 border border-cyan-500 text-cyan-300 hover:bg-cyan-800 text-xs font-bold py-2 rounded uppercase flex items-center justify-center gap-1"
              >
                {apreSuggestion.type === "INCREASE" ? (
                  <ArrowUp className="w-3 h-3" />
                ) : (
                  <ArrowDown className="w-3 h-3" />
                )}
                {apreSuggestion.adjustment > 0 ? "+" : ""}
                {apreSuggestion.adjustment}kg
              </button>
              <button
                onClick={() => setApreSuggestion(null)}
                className="px-3 border border-zinc-700 text-zinc-500 hover:text-white rounded"
              >
                <X className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MANA BAR OVERLAY */}
      <div className="absolute top-0 left-0 right-0 h-1 bg-zinc-900 z-50">
        <div
          className={`h-full transition-all duration-500 ease-out ${manaColor} shadow-[0_0_10px_currentColor]`}
          style={{ width: `${manaPct}%` }}
        />
      </div>

      {lastCommand && (
        <div className="fixed top-20 left-1/2 -translate-x-1/2 z-50 bg-black/80 border border-zinc-700 px-4 py-2 rounded text-xs font-mono text-green-400 animate-fade-in-out">
          &gt; {lastCommand}
        </div>
      )}

      {manaDrain.show && (
        <div className="fixed top-20 right-10 text-red-500 font-black text-2xl animate-float-up z-50 text-shadow-sm font-serif">
          -{manaDrain.amount} Mana
        </div>
      )}

      {isManaEmpty && (
        <div className="fixed inset-0 z-0 pointer-events-none bg-red-900/10 animate-pulse flex items-center justify-center">
          <div className="text-red-500/20 font-black text-9xl uppercase rotate-[-15deg]">
            Soul Burn
          </div>
        </div>
      )}

      {criticalHit.show && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center pointer-events-none">
          <div className="flex flex-col items-center animate-scale-bounce">
            <div
              className="text-6xl font-black italic text-[#ffd700] uppercase tracking-tighter drop-shadow-[0_0_15px_rgba(255,215,0,0.8)] stroke-black"
              style={{ WebkitTextStroke: "2px black" }}
            >
              Critical Hit!
            </div>
            <div className="text-2xl font-bold text-white mt-2 bg-red-600 px-4 py-1 rounded skew-x-[-12deg] shadow-lg">
              {criticalHit.msg}
            </div>
          </div>
        </div>
      )}

      <div className="px-6 py-4 border-b border-zinc-900 bg-zinc-950/80 flex justify-between items-center sticky top-0 z-10 backdrop-blur-md">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <span
              className={`w-2 h-2 rotate-45 border ${isSystemOverheated ? "border-orange-500 bg-orange-900" : "border-green-500 bg-green-900"}`}
            ></span>
            <span
              className={`${isSystemOverheated ? "text-orange-500" : "text-green-500"} font-serif text-xs uppercase tracking-widest`}
            >
              {isSystemOverheated ? "Aggro High" : "Stealth Mode"}
            </span>
          </div>
          <h2 className="text-xl font-serif font-bold text-zinc-100 uppercase tracking-wide text-shadow-sm">
            {block.name}
          </h2>
        </div>

        <div className="flex gap-4 items-center">
          <div className="hidden md:flex flex-col items-end">
            <div className="flex items-center gap-1 text-[10px] font-bold uppercase text-zinc-500">
              <Battery className="w-3 h-3" /> Body Battery
            </div>
            <span
              className={`font-mono font-bold text-lg ${manaPct < 30 ? "text-red-500" : "text-blue-400"}`}
            >
              {mana} / {maxMana}
            </span>
          </div>

          <div className="h-8 w-px bg-zinc-800 hidden md:block"></div>

          <div className="flex gap-2">
            <button
              onClick={() => setIsNeuroActive(!isNeuroActive)}
              className={`p-2 border rounded transition-colors group relative ${isNeuroActive ? "bg-purple-900/50 border-purple-500 text-purple-400" : "bg-zinc-900 border-zinc-800 text-zinc-400 hover:text-white"}`}
              title="Neuro-Link (Binaural Beats)"
            >
              <Waves className="w-5 h-5" />
            </button>
            <button
              onClick={() => setShowVision(!showVision)}
              className={`p-2 border rounded transition-colors group relative ${showVision ? "bg-cyan-900/50 border-cyan-500 text-cyan-400" : "bg-zinc-900 border-zinc-800 text-zinc-400 hover:text-white"}`}
              title="Titan Vision (Rep Count)"
            >
              <Camera className="w-5 h-5" />
            </button>
            <button
              onClick={toggleListening}
              className={`p-2 border rounded transition-colors group relative ${isListening ? "bg-red-900/50 border-red-500 text-red-400 animate-pulse" : "bg-zinc-900 border-zinc-800 text-zinc-400 hover:text-white"}`}
              title="Voice Commands"
            >
              <Mic className="w-5 h-5" />
            </button>
            <button
              onClick={onAbort}
              className="p-2 border border-red-900/30 bg-red-950/10 rounded text-red-700 hover:text-red-500 hover:border-red-600 transition-colors"
              title="Abandon Quest"
            >
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-8 scroll-smooth pb-32">
        <VisionRepCounter
          isActive={showVision}
          onRepCount={handleVisionRep}
          onClose={() => setShowVision(false)}
        />
        <HeartRateMonitor
          bpm={bpm}
          isConnected={isBtConnected}
          onConnect={onBtConnect}
          onSimulate={onBtSimulate}
          error={btError}
          hasAura={isElite}
        />

        <div
          className={`grid gap-6 ${exercises.length > 1 ? "lg:grid-cols-2" : "grid-cols-1"}`}
        >
          {exercises.map((ex, exIndex) => {
            const isLandmine = ex.name.toLowerCase().includes("landmine");
            const isInfoOpen = openInfoId === ex.id;
            const isAmrapEx = ex.sets.some((s) => typeof s.reps === "string");
            const showPrimalRoar = hasPrimalRoar && isAmrapEx;

            return (
              <div key={ex.id} className="space-y-4">
                <div className="flex items-end justify-between border-b border-zinc-900 pb-2">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-zinc-900 border border-zinc-800 rounded relative">
                      <Sword className="w-5 h-5 text-zinc-400" />
                      {showPrimalRoar && (
                        <div className="absolute -top-1 -right-1 bg-red-500 rounded-full p-0.5 animate-pulse">
                          <Flame className="w-2 h-2 text-white fill-current" />
                        </div>
                      )}
                    </div>
                    <div>
                      <h3 className="text-lg font-serif font-bold text-zinc-200">
                        {ex.name}
                      </h3>
                      {showPrimalRoar && (
                        <span className="text-[9px] font-bold uppercase text-red-500 tracking-wider flex items-center gap-1">
                          <Flame className="w-3 h-3" /> Primal Roar Active
                        </span>
                      )}
                    </div>
                    <button
                      onClick={() => setOpenInfoId(isInfoOpen ? null : ex.id)}
                      className={`p-1 rounded hover:bg-zinc-800 transition-colors ${isInfoOpen ? "text-rarity-epic" : "text-zinc-600"}`}
                    >
                      <Info className="w-5 h-5" />
                    </button>
                  </div>
                  {ex.logic === ExerciseLogic.TM_PERCENT && (
                    <span className="text-xs font-mono text-zinc-600">
                      TM: {ex.trainingMax}
                    </span>
                  )}
                </div>

                {isInfoOpen && (
                  <div className="bg-[#111] border border-zinc-800 rounded p-4 text-sm animate-fade-in mb-4 shadow-xl">
                    {ex.instructions && (
                      <ul className="space-y-2 mb-4">
                        {ex.instructions.map((inst, i) => (
                          <li key={i} className="flex gap-2 text-zinc-400">
                            <span className="text-zinc-600 font-mono">
                              0{i + 1}.
                            </span>
                            <span className="font-serif italic">{inst}</span>
                          </li>
                        ))}
                      </ul>
                    )}
                  </div>
                )}

                <div className="space-y-3">
                  {ex.sets.map((set, setIndex) => {
                    let displayWeight = set.weight || 0;
                    if (
                      ex.logic === ExerciseLogic.TM_PERCENT &&
                      ex.trainingMax &&
                      set.weightPct
                    ) {
                      displayWeight = roundToPlates(
                        ex.trainingMax * set.weightPct,
                      );
                    }
                    const isLocked = !set.completed && isSystemOverheated;
                    const isFocused =
                      cursor[0] === exIndex && cursor[1] === setIndex;
                    const displayRarity =
                      set.completed && set.rarity
                        ? set.rarity
                        : calculateRarity(set, ex.logic);

                    return (
                      <SetRow
                        key={set.id}
                        set={set}
                        exIndex={exIndex}
                        setIndex={setIndex}
                        isFocused={isFocused}
                        isLocked={isLocked}
                        displayWeight={displayWeight}
                        isLandmine={isLandmine}
                        rarity={displayRarity}
                        onToggle={handleToggleSet}
                        onRepsChange={handleRepsChange}
                        onWeightChange={handleWeightChange}
                        onRpeChange={handleRpeChange}
                        previous={previousStats[ex.id]} // Simplified: same previous for all sets of same exercise
                        activeSetRef={isFocused ? activeSetRef : null}
                      />
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>

        <div className="text-center text-zinc-700 text-xs font-serif uppercase tracking-widest mt-8 flex flex-col gap-3">
          <button
            onClick={() => setOpenInfoId("ADD_EXERCISE")} // repurposed for modal
            className="flex items-center justify-center gap-2 py-3 px-6 bg-zinc-900 border border-zinc-800 rounded mx-auto hover:bg-zinc-800 hover:text-white transition-all text-zinc-500 font-bold w-full max-w-xs"
          >
            <Plus className="w-4 h-4" /> Add Exercise
          </button>
          <span>[ WASD Controls Active ]</span>
        </div>
      </div>

      {/* EXERCISE LIBRARY MODAL */}
      {openInfoId === "ADD_EXERCISE" && (
        <div className="fixed inset-0 z-[100] animate-fade-in">
          <ExerciseLibrary
            onSelect={(exId) => {
              // Mock adding exercise logic - needing real exercise data lookup
              // For now, we will just add a dummy "New Exercise" or fetch from Library logic
              // Since ExerciseLibrary has mock data, we need to map it to our Exercise type

              const newExercise: Exercise = {
                id: exId + "_" + Date.now(),
                name: "New Exercise", // Should get from library
                logic: ExerciseLogic.FIXED_REPS,
                sets: [
                  {
                    id: "new_set_1",
                    reps: 10,
                    weight: 20,
                    completed: false,
                    type: "straight",
                  },
                  {
                    id: "new_set_2",
                    reps: 10,
                    weight: 20,
                    completed: false,
                    type: "straight",
                  },
                  {
                    id: "new_set_3",
                    reps: 10,
                    weight: 20,
                    completed: false,
                    type: "straight",
                  },
                ],
              };
              setExercises((prev) => [...prev, newExercise]);
              setOpenInfoId(null);
              playSound("quest_accept");
            }}
            onClose={() => setOpenInfoId(null)}
          />
        </div>
      )}

      <div className="p-6 bg-zinc-950 border-t border-zinc-900 sticky bottom-0 z-40">
        <div className="flex items-center justify-between mb-2 text-[10px] font-bold uppercase tracking-widest text-zinc-600">
          <span>Potential XP: {isRested ? "Double (Rested)" : "Normal"}</span>
          <span>Mana Status: {isManaEmpty ? "DEPLETED" : "Stable"}</span>
        </div>

        <button
          onClick={() => {
            if (isBlockComplete && !isSystemOverheated && !isManaEmpty) {
              playSound("ding");
              onComplete();
            }
          }}
          disabled={!isBlockComplete || isSystemOverheated || isManaEmpty}
          className={`w-full h-16 font-serif font-black text-xl uppercase tracking-widest rounded flex items-center justify-center gap-3 transition-all border-2 
             ${isBlockComplete && !isSystemOverheated && !isManaEmpty
              ? "bg-rarity-legendary/10 border-rarity-legendary text-rarity-legendary hover:bg-rarity-legendary hover:text-white shadow-[0_0_30px_rgba(255,128,0,0.2)]"
              : "bg-zinc-900 border-zinc-800 text-zinc-600 cursor-not-allowed"
            }`}
        >
          {isManaEmpty
            ? "Mana Depleted - Recover!"
            : isBlockComplete
              ? isSystemOverheated
                ? "Wait for Aggro Drop"
                : "Complete Quest Step"
              : "Objectives Remaining"}
          {isBlockComplete && !isSystemOverheated && !isManaEmpty && (
            <Crown className="w-6 h-6" />
          )}
        </button>
      </div>

      <style>{`
        @keyframes floatUp {
            0% { transform: translateY(0); opacity: 1; }
            100% { transform: translateY(-50px); opacity: 0; }
        }
        .animate-float-up {
            animation: floatUp 1s ease-out forwards;
        }
        @keyframes fadeOut {
            0% { opacity: 1; }
            80% { opacity: 1; }
            100% { opacity: 0; }
        }
        .animate-fade-in-out {
            animation: fadeOut 2s forwards;
        }
        @keyframes slideLeft {
            from { transform: translateX(100%); opacity: 0; }
            to { transform: translateX(0); opacity: 1; }
        }
        .animate-slide-left {
            animation: slideLeft 0.3s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default ActionView;

import React, { useState } from "react";
import {
  Session,
  Block,
  BlockType,
  Exercise,
  ExerciseLogic,
} from "@/types";
import {
  Plus,
  Trash2,
  Save,
  Dumbbell,
  ArrowDown,
  ChevronUp,
  ChevronDown,
} from "lucide-react";

interface DungeonBuilderProps {
  onSave: (session: Session) => void;
  onCancel: () => void;
}

const DungeonBuilder: React.FC<DungeonBuilderProps> = ({
  onSave,
  onCancel,
}) => {
  const [name, setName] = useState("");
  const [zoneName, setZoneName] = useState("");
  const [blocks, setBlocks] = useState<Block[]>([]);

  const addBlock = (type: BlockType) => {
    const newBlock: Block = {
      id: `blk_${Date.now()}`,
      name: type === BlockType.TRANSITION ? "Transition Area" : "New Station",
      type,
      exercises: type === BlockType.STATION ? [] : undefined,
      setupInstructions:
        type === BlockType.TRANSITION ? ["Setup instruction 1"] : undefined,
    };
    setBlocks([...blocks, newBlock]);
  };

  const removeBlock = (index: number) => {
    setBlocks(blocks.filter((_, i) => i !== index));
  };

  const moveBlock = (index: number, direction: "UP" | "DOWN") => {
    if (direction === "UP" && index === 0) return;
    if (direction === "DOWN" && index === blocks.length - 1) return;

    const newBlocks = [...blocks];
    const targetIndex = direction === "UP" ? index - 1 : index + 1;
    const temp = newBlocks[targetIndex];
    newBlocks[targetIndex] = newBlocks[index];
    newBlocks[index] = temp;
    setBlocks(newBlocks);
  };

  const addExercise = (blockIndex: number) => {
    const newEx: Exercise = {
      id: `ex_${Date.now()}`,
      name: "New Exercise",
      logic: ExerciseLogic.FIXED_REPS,
      sets: [
        { id: `s_${Date.now()}_1`, reps: 10, completed: false },
        { id: `s_${Date.now()}_2`, reps: 10, completed: false },
        { id: `s_${Date.now()}_3`, reps: 10, completed: false },
      ],
      instructions: ["Perform with perfect form."],
    };

    const updatedBlocks = [...blocks];
    if (!updatedBlocks[blockIndex].exercises)
      updatedBlocks[blockIndex].exercises = [];
    updatedBlocks[blockIndex].exercises!.push(newEx);
    setBlocks(updatedBlocks);
  };

  const updateExercise = (
    bIdx: number,
    eIdx: number,
    field: keyof Exercise,
    value: any,
  ) => {
    const updatedBlocks = [...blocks];
    updatedBlocks[bIdx].exercises![eIdx] = {
      ...updatedBlocks[bIdx].exercises![eIdx],
      [field]: value,
    };
    setBlocks(updatedBlocks);
  };

  const handleSave = () => {
    if (!name) return alert("Dungeon must have a name!");
    const session: Session = {
      id: `custom_${Date.now()}`,
      name,
      zoneName: zoneName || "The Player Realm",
      difficulty: "Normal",
      blocks,
      isCustom: true,
    };
    onSave(session);
  };

  return (
    <div className="h-full bg-[#050505] p-6 overflow-y-auto font-serif text-zinc-200">
      <h1 className="text-3xl font-black text-[#c79c6e] mb-6 border-b border-[#46321d] pb-4">
        Dungeon Architect
      </h1>

      <div className="space-y-4 mb-8">
        <div className="space-y-1">
          <label className="text-xs font-bold uppercase text-zinc-500">
            Dungeon Name
          </label>
          <input
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="w-full bg-[#111] border border-zinc-700 p-3 rounded focus:border-[#c79c6e] focus:outline-none"
            placeholder="e.g. The Iron Fortress"
          />
        </div>
        <div className="space-y-1">
          <label className="text-xs font-bold uppercase text-zinc-500">
            Zone / Flavor Text
          </label>
          <input
            value={zoneName}
            onChange={(e) => setZoneName(e.target.value)}
            className="w-full bg-[#111] border border-zinc-700 p-3 rounded focus:border-[#c79c6e] focus:outline-none"
            placeholder="e.g. A dark cavern filled with heavy weights..."
          />
        </div>
      </div>

      <div className="space-y-6">
        {blocks.map((block, bIdx) => (
          <div
            key={block.id}
            className="bg-[#1a1a1a] border border-zinc-800 rounded-lg p-4 relative group transition-all"
          >
            <div className="absolute top-2 right-2 flex gap-1">
              <button
                onClick={() => moveBlock(bIdx, "UP")}
                disabled={bIdx === 0}
                className="p-1 text-zinc-600 hover:text-white disabled:opacity-30 disabled:hover:text-zinc-600"
              >
                <ChevronUp className="w-4 h-4" />
              </button>
              <button
                onClick={() => moveBlock(bIdx, "DOWN")}
                disabled={bIdx === blocks.length - 1}
                className="p-1 text-zinc-600 hover:text-white disabled:opacity-30 disabled:hover:text-zinc-600"
              >
                <ChevronDown className="w-4 h-4" />
              </button>
              <div className="w-px h-4 bg-zinc-700 mx-1 self-center"></div>
              <button
                onClick={() => removeBlock(bIdx)}
                className="p-1 text-zinc-600 hover:text-red-500"
              >
                <Trash2 className="w-4 h-4" />
              </button>
            </div>

            <div className="mb-4 pr-24">
              <input
                value={block.name}
                onChange={(e) => {
                  const newBlocks = [...blocks];
                  newBlocks[bIdx].name = e.target.value;
                  setBlocks(newBlocks);
                }}
                className="bg-transparent text-xl font-bold text-white focus:outline-none w-full"
              />
              <span className="text-[10px] uppercase font-bold text-[#c79c6e] bg-[#c79c6e]/10 px-2 py-0.5 rounded">
                {block.type}
              </span>
            </div>

            {block.type === BlockType.STATION && (
              <div className="space-y-4 pl-4 border-l-2 border-zinc-800">
                {block.exercises?.map((ex, eIdx) => (
                  <div key={ex.id} className="space-y-2">
                    <div className="flex items-center gap-2">
                      <Dumbbell className="w-4 h-4 text-zinc-500" />
                      <input
                        value={ex.name}
                        onChange={(e) =>
                          updateExercise(bIdx, eIdx, "name", e.target.value)
                        }
                        className="bg-[#111] border border-zinc-700 p-1 rounded text-sm w-full"
                      />
                    </div>
                    <div className="flex gap-2">
                      {ex.sets.map((set, sIdx) => (
                        <div
                          key={set.id}
                          className="bg-zinc-900 px-2 py-1 rounded text-xs border border-zinc-800"
                        >
                          Set {sIdx + 1}: {set.reps} reps
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
                <button
                  onClick={() => addExercise(bIdx)}
                  className="text-xs text-zinc-500 hover:text-[#c79c6e] flex items-center gap-1"
                >
                  <Plus className="w-3 h-3" /> Add Monster (Exercise)
                </button>
              </div>
            )}

            {block.type === BlockType.TRANSITION && (
              <textarea
                className="w-full bg-[#111] text-xs text-zinc-400 p-2 rounded"
                placeholder="Setup instructions..."
                value={block.setupInstructions?.join("\n")}
                onChange={(e) => {
                  const newBlocks = [...blocks];
                  newBlocks[bIdx].setupInstructions =
                    e.target.value.split("\n");
                  setBlocks(newBlocks);
                }}
              />
            )}
          </div>
        ))}
      </div>

      <div className="mt-8 grid grid-cols-2 gap-4">
        <button
          onClick={() => addBlock(BlockType.STATION)}
          className="py-4 border-2 border-dashed border-zinc-700 text-zinc-500 hover:border-[#c79c6e] hover:text-[#c79c6e] rounded flex justify-center items-center gap-2 uppercase font-bold text-xs"
        >
          <Plus className="w-4 h-4" /> Add Station
        </button>
        <button
          onClick={() => addBlock(BlockType.TRANSITION)}
          className="py-4 border-2 border-dashed border-zinc-700 text-zinc-500 hover:border-blue-500 hover:text-blue-500 rounded flex justify-center items-center gap-2 uppercase font-bold text-xs"
        >
          <ArrowDown className="w-4 h-4" /> Add Transition
        </button>
      </div>

      <div className="mt-8 flex gap-4 sticky bottom-0 bg-[#050505] py-4 border-t border-zinc-900">
        <button
          onClick={onCancel}
          className="flex-1 py-3 text-zinc-500 hover:text-white"
        >
          Cancel
        </button>
        <button
          onClick={handleSave}
          className="flex-1 py-3 bg-[#c79c6e] hover:bg-[#d4a87a] text-[#46321d] font-bold uppercase tracking-widest rounded flex items-center justify-center gap-2"
        >
          <Save className="w-4 h-4" /> Save Dungeon
        </button>
      </div>
    </div>
  );
};

export default DungeonBuilder;

import React, { useState, useEffect } from "react";
import {
  Cloud,
  X,
  Shield,
  RefreshCw,
  CheckCircle2,
  Server,
  Wifi,
} from "lucide-react";
import { ValhallaPayload } from "@/types";
import { ValhallaService } from "@/services/valhalla";
import { playSound } from "@/utils";
import { useSkills } from "@/context/SkillContext";

interface ValhallaGateProps {
  isOpen: boolean;
  onClose: () => void;
  heroName: string | undefined;
  onBind: (name: string, id: string) => void;
  syncPayload: ValhallaPayload | null; // Partial payload from App
}

const ValhallaGate: React.FC<ValhallaGateProps> = ({
  isOpen,
  onClose,
  heroName,
  onBind,
  syncPayload,
}) => {
  const [step, setStep] = useState<"BIND" | "IDLE" | "SYNCING" | "SUCCESS">(
    "BIND",
  );
  const [inputName, setInputName] = useState(heroName || "");
  const [logs, setLogs] = useState<string[]>([]);

  // Integrate Skills Context
  const { purchasedSkillIds } = useSkills();

  // Construct final payload with skills
  const finalPayload: ValhallaPayload | null = syncPayload
    ? {
      ...syncPayload,
      skills: Array.from(purchasedSkillIds),
    }
    : null;

  useEffect(() => {
    if (isOpen) {
      if (heroName) {
        setStep("IDLE");
      } else {
        setStep("BIND");
      }
      setLogs([]);
    }
  }, [isOpen, heroName]);

  const addLog = (msg: string) => setLogs((prev) => [...prev, msg]);

  const handleBind = async () => {
    if (!inputName) return;
    setStep("SYNCING");
    addLog("Initiating Soul Bind Protocol...");

    const res = await ValhallaService.bindSoul(inputName);

    if (res.success) {
      playSound("quest_accept");
      addLog(`Identity Confirmed. Welcome, ${inputName}.`);
      addLog(`Valhalla ID Assigned: ${res.id}`);
      onBind(inputName, res.id);
      // Step transition handled by useEffect on heroName change
    }
  };

  const handleSync = async () => {
    if (!finalPayload) return;
    setStep("SYNCING");
    playSound("quest_accept");
    addLog("Opening Bifrost Gate...");
    addLog("Compressing Soul Data...");

    const res = await ValhallaService.engraveRecords(finalPayload);

    if (res.success) {
      playSound("achievement");
      addLog("Success: " + res.message);
      setStep("SUCCESS");
      setTimeout(() => {
        onClose();
      }, 2000);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-[#050505]/90 backdrop-blur-md animate-fade-in p-4">
      <div className="w-full max-w-md bg-[#0a0f14] border-2 border-cyan-900 rounded-lg shadow-[0_0_50px_rgba(8,145,178,0.2)] overflow-hidden font-serif relative">
        {/* Valhalla Texture */}
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10 pointer-events-none"></div>

        {/* Header */}
        <div className="relative bg-gradient-to-r from-cyan-950 to-[#0a0f14] p-6 border-b border-cyan-900/50 flex justify-between items-start">
          <div>
            <div className="flex items-center gap-2 text-cyan-400 mb-1">
              <Cloud className="w-6 h-6" />
              <h2 className="font-bold uppercase tracking-[0.2em] text-sm">
                Project Valhalla
              </h2>
            </div>
            <p className="text-cyan-700 text-[10px] font-sans">
              IronForge Cloud Services (v1.0)
            </p>
          </div>
          <button
            onClick={onClose}
            className="text-cyan-800 hover:text-cyan-400 transition-colors"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        {/* Content */}
        <div className="p-8 space-y-6 relative z-10">
          {/* STEP 1: BIND SOUL (Login) */}
          {step === "BIND" && (
            <div className="space-y-4 animate-slide-up">
              <div className="text-center">
                <div className="w-20 h-20 bg-cyan-900/20 border border-cyan-500 rounded-full flex items-center justify-center mx-auto mb-4 shadow-[0_0_20px_rgba(6,182,212,0.3)] animate-pulse">
                  <Shield className="w-10 h-10 text-cyan-400" />
                </div>
                <h3 className="text-cyan-100 font-bold uppercase tracking-widest mb-2">
                  Bind Your Soul
                </h3>
                <p className="text-cyan-500/60 text-xs font-sans max-w-xs mx-auto">
                  Create a permanent link to the Hall of Records to enable
                  cross-device progression.
                </p>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold uppercase text-cyan-700 tracking-widest">
                  Hero Name
                </label>
                <input
                  value={inputName}
                  onChange={(e) => setInputName(e.target.value)}
                  className="w-full bg-[#050505] border border-cyan-900 p-3 text-cyan-100 focus:border-cyan-500 focus:outline-none rounded font-mono text-center uppercase tracking-widest"
                  placeholder="ENTER NAME"
                />
              </div>
              <button
                onClick={handleBind}
                disabled={!inputName}
                className="w-full py-4 bg-cyan-900/30 border border-cyan-600 text-cyan-400 hover:bg-cyan-800/40 font-bold uppercase tracking-widest rounded transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Engrave Name
              </button>
            </div>
          )}

          {/* STEP 2: DASHBOARD (Sync) */}
          {step === "IDLE" && (
            <div className="space-y-6 animate-slide-up">
              <div className="flex items-center justify-between bg-cyan-950/20 p-4 rounded border border-cyan-900/30">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 bg-cyan-900 rounded-full flex items-center justify-center text-cyan-200 font-bold text-lg">
                    {inputName.charAt(0)}
                  </div>
                  <div>
                    <div className="text-cyan-100 font-bold uppercase text-sm">
                      {inputName}
                    </div>
                    <div className="text-cyan-700 text-[10px] flex items-center gap-1">
                      <Wifi className="w-3 h-3" /> Connected
                    </div>
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-[10px] text-cyan-600 uppercase">
                    Cloud Status
                  </div>
                  <div className="text-cyan-400 font-bold text-xs">Ready</div>
                </div>
              </div>

              <div className="space-y-2">
                <h4 className="text-[10px] font-bold uppercase text-cyan-800 border-b border-cyan-900/50 pb-1">
                  Pending Upload
                </h4>
                <div className="grid grid-cols-2 gap-2 text-xs text-cyan-600 font-mono">
                  <div>
                    XP Level:{" "}
                    <span className="text-cyan-300">
                      {finalPayload?.level || 0}
                    </span>
                  </div>
                  <div>
                    Achievements:{" "}
                    <span className="text-cyan-300">
                      {finalPayload?.achievements.length || 0}
                    </span>
                  </div>
                  <div>
                    Talents:{" "}
                    <span className="text-cyan-300">
                      {finalPayload?.skills.length || 0}
                    </span>
                  </div>
                  <div>
                    Logs:{" "}
                    <span className="text-cyan-300">
