"use client";

import React, { useState, useEffect, useCallback } from "react";
import { TerritoryCard } from "./TerritoryCard";
import {
    getTerritoriesAction,
    claimTerritoryAction,
    contestTerritoryAction
} from "@/actions/game/territory";
import { Loader2, RefreshCw } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

interface TerritoryMapProps {
    userId: string;
    guildId?: string;
}

export const TerritoryMap: React.FC<TerritoryMapProps> = ({ userId, guildId }) => {
    const [territories, setTerritories] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [busyId, setBusyId] = useState<string | null>(null);
    const { toast } = useToast();

    const loadData = useCallback(async () => {
        setLoading(true);
        try {
            const data = await getTerritoriesAction();
            setTerritories(data);
        } catch (err) {
            toast({
                title: "Error",
                description: "Failed to load territory map",
                variant: "destructive",
            });
        } finally {
            setLoading(false);
        }
    }, [toast]);

    useEffect(() => {
        loadData();
    }, [loadData]);

    const handleClaim = async (id: string) => {
        if (!guildId) return;
        setBusyId(id);
        try {
            await claimTerritoryAction(guildId, id, userId);
            toast({ title: "Success", description: "Territory claimed for your guild!" });
            loadData();
        } catch (err: any) {
            toast({
                title: "Claim Failed",
                description: err.message,
                variant: "destructive",
            });
        } finally {
            setBusyId(null);
        }
    };

    const handleContest = async (id: string) => {
        if (!guildId) return;
        setBusyId(id);
        try {
            await contestTerritoryAction(guildId, id, userId);
            toast({ title: "Challenge Issued!", description: "Contest started. Log workouts to win!" });
            loadData();
        } catch (err: any) {
            toast({
                title: "Contest Failed",
                description: err.message,
                variant: "destructive",
            });
        } finally {
            setBusyId(null);
        }
    };

    if (loading && territories.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center py-20 bg-zinc-900/50 border border-white/5 rounded-xl">
                <Loader2 className="w-8 h-8 text-magma animate-spin mb-4" />
                <span className="text-zinc-500 font-bold uppercase tracking-widest text-xs">Synchronizing Map...</span>
            </div>
        );
    }

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-end">
                <div>
                    <h2 className="text-2xl font-black text-white italic uppercase tracking-tighter">Strategic Map</h2>
                    <p className="text-sm text-zinc-500">Conquer territories to earn guild-wide bonuses.</p>
                </div>
                <button
                    onClick={loadData}
                    disabled={loading}
                    aria-label="Refresh territory data"
                    title="Refresh territory data"
                    className="p-2 hover:bg-white/5 rounded-full transition-colors group"
                >
                    <RefreshCw className={`w-4 h-4 text-zinc-500 group-hover:text-magma ${loading ? 'animate-spin' : ''}`} />
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {territories.map((t) => (
                    <TerritoryCard
                        key={t.id}
                        territory={t}
                        userGuildId={guildId}
                        onClaim={handleClaim}
                        onContest={handleContest}
                        isLoading={busyId === t.id}
                    />
                ))}
            </div>

            {territories.length === 0 && !loading && (
                <div className="text-center py-10 bg-zinc-900 border border-white/5 rounded-xl italic text-zinc-600">
                    The map is currently empty. Discovery in progress...
                </div>
            )}
        </div>
    );
};

"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, Lightbulb, ChevronRight } from "lucide-react";
import { Button } from "@/components/ui/button";

interface HintConfig {
  id: string;
  targetSelector: string;
  title: string;
  message: string;
  position?: "top" | "bottom" | "left" | "right";
}

const FIRST_TIME_HINTS: HintConfig[] = [
  {
    id: "dashboard_stats",
    targetSelector: '[data-hint="titan-stats"]',
    title: "Your Titan Stats",
    message:
      "Track your Titan's health, energy, and XP here. Keep training to level up!",
    position: "bottom",
  },
  {
    id: "start_workout",
    targetSelector: '[data-hint="start-workout"]',
    title: "Begin Your Journey",
    message:
      "Tap here to start a workout session. Each set you complete deals damage to dungeon bosses!",
    position: "top",
  },
  {
    id: "skill_tree",
    targetSelector: '[data-hint="skill-tree"]',
    title: "Unlock Skills",
    message:
      "Spend skill points to unlock passive bonuses and combat abilities.",
    position: "left",
  },
  {
    id: "streak_badge",
    targetSelector: '[data-hint="streak"]',
    title: "Daily Streak",
    message: "Train every day to maintain your streak and earn bonus XP!",
    position: "bottom",
  },
];

const STORAGE_KEY = "ironforge_seen_hints";

export function useFirstTimeHints() {
  const [seenHints, setSeenHints] = useState<Set<string>>(new Set());
  const [currentHint, setCurrentHint] = useState<HintConfig | null>(null);

  useEffect(() => {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      setSeenHints(new Set(JSON.parse(stored)));
    }
  }, []);

  const showNextHint = () => {
    const unseen = FIRST_TIME_HINTS.filter((h) => !seenHints.has(h.id));
    if (unseen.length > 0) {
      setCurrentHint(unseen[0]);
    }
  };

  const dismissHint = (hintId: string) => {
    const newSeen = new Set(seenHints).add(hintId);
    setSeenHints(newSeen);
    localStorage.setItem(STORAGE_KEY, JSON.stringify([...newSeen]));
    setCurrentHint(null);
  };

  const dismissAll = () => {
    const allIds = new Set(FIRST_TIME_HINTS.map((h) => h.id));
    setSeenHints(allIds);
    localStorage.setItem(STORAGE_KEY, JSON.stringify([...allIds]));
    setCurrentHint(null);
  };

  const resetHints = () => {
    setSeenHints(new Set());
    localStorage.removeItem(STORAGE_KEY);
  };

  return {
    currentHint,
    showNextHint,
    dismissHint,
    dismissAll,
    resetHints,
    hasUnseenHints: FIRST_TIME_HINTS.some((h) => !seenHints.has(h.id)),
  };
}

interface HintOverlayProps {
  hint: HintConfig;
  onDismiss: () => void;
  onSkipAll: () => void;
}

export function HintOverlay({ hint, onDismiss, onSkipAll }: HintOverlayProps) {
  return (
    <AnimatePresence>
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        className="fixed inset-0 z-[100] pointer-events-none"
      >
        {/* Backdrop */}
        <div
          className="absolute inset-0 bg-black/60 pointer-events-auto"
          onClick={onDismiss}
        />

        {/* Hint Card */}
        <motion.div
          initial={{ opacity: 0, y: 20, scale: 0.95 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          exit={{ opacity: 0, y: 20, scale: 0.95 }}
          className="absolute bottom-20 left-1/2 -translate-x-1/2 w-[90%] max-w-sm pointer-events-auto"
        >
          <div className="bg-slate-900 border border-amber-500/50 rounded-xl p-4 shadow-[0_0_30px_rgba(251,191,36,0.2)]">
            <div className="flex items-start gap-3">
              <div className="flex-shrink-0 w-10 h-10 rounded-full bg-amber-500/20 flex items-center justify-center">
                <Lightbulb className="w-5 h-5 text-amber-400" />
              </div>
              <div className="flex-1">
                <h3 className="font-bold text-white text-sm">{hint.title}</h3>
                <p className="text-slate-400 text-xs mt-1 leading-relaxed">
                  {hint.message}
                </p>
              </div>
              <button
                onClick={onDismiss}
                className="text-slate-500 hover:text-white"
              >
                <X className="w-4 h-4" />
              </button>
            </div>

            <div className="flex justify-between items-center mt-4 pt-3 border-t border-slate-800">
              <button
                onClick={onSkipAll}
                className="text-xs text-slate-500 hover:text-slate-300"
              >
                Skip all hints
              </button>
              <Button size="sm" onClick={onDismiss} className="gap-1">
                Got it <ChevronRight className="w-3 h-3" />
              </Button>
            </div>
          </div>
        </motion.div>
      </motion.div>
    </AnimatePresence>
  );
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast";

interface PocketCastsAuthProps {
    onSuccess?: () => void;
}

export function PocketCastsAuth({ onSuccess }: PocketCastsAuthProps) {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [isLoading, setIsLoading] = useState(false);
    const { toast } = useToast();

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);

        try {
            const res = await fetch("/api/podcast/login", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ email, password }),
            });

            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.error || "Login failed");
            }

            toast({
                title: "Connected!",
                description: "Your Pocket Casts account is now linked.",
            });

            onSuccess?.();
        } catch (error: any) {
            toast({
                variant: "destructive",
                title: "Connection Failed",
                description: error.message,
            });
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <Card className="w-full max-w-md mx-auto">
            <CardHeader>
                <CardTitle>Connect Pocket Casts</CardTitle>
                <CardDescription>
                    Enter your Pocket Casts credentials to access your podcasts during workouts.
                </CardDescription>
            </CardHeader>
            <form onSubmit={handleLogin}>
                <CardContent className="space-y-4">
                    <div className="space-y-2">
                        <label className="text-sm font-medium">Email</label>
                        <Input
                            type="email"
                            placeholder="email@example.com"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-sm font-medium">Password</label>
                        <Input
                            type="password"
                            placeholder="••••••••"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                        />
                    </div>
                    <p className="text-xs text-muted-foreground italic">
                        Note: If you use Google or Apple to log in, you must set a password in Pocket Casts first.
                    </p>
                </CardContent>
                <CardFooter>
                    <Button type="submit" className="w-full" disabled={isLoading}>
                        {isLoading ? "Connecting..." : "Connect Account"}
                    </Button>
                </CardFooter>
            </form>
        </Card>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { createDuelChallengeAction, getPotentialOpponentsAction } from "@/actions/pvp/duel";
import { toast } from "sonner";
import { Bike, Footprints, Trophy } from "lucide-react";

interface Opponent {
    id: string;
    heroName: string;
    level: number;
    titan?: { powerRating: number };
}

export function CardioDuelLobby() {
    const [opponents, setOpponents] = useState<Opponent[]>([]);
    const [selectedOpponent, setSelectedOpponent] = useState<string | null>(null);
    const [duelType, _setDuelType] = useState("DISTANCE_RACE");
    const [activityType, setActivityType] = useState("RUNNING");
    const [distance, setDistance] = useState("5");
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        loadOpponents();
    }, []);

    const loadOpponents = async () => {
        const res = await getPotentialOpponentsAction();
        if (res.success && res.opponents) {
            // Fix: Map to ensure heroName is string (fallback for null)
            const sanitized: Opponent[] = res.opponents.map((opp: any) => ({
                id: opp.id,
                heroName: opp.heroName || "Unknown Titan",
                level: opp.level, // Assuming level is always present/valid based on schema, otherwise provide default
                titan: opp.titan ? { powerRating: opp.titan.powerRating } : undefined
            }));
            setOpponents(sanitized);
        }
    };

    const handleCreateDuel = async () => {
        if (!selectedOpponent) return;
        setLoading(true);

        const result = await createDuelChallengeAction(selectedOpponent, {
            duelType,
            activityType,
            targetDistance: parseFloat(distance),
        });

        if (result.success) {
            toast.success("Duel Challenge Sent!");
            setSelectedOpponent(null);
        } else {
            toast.error(result.error);
        }
        setLoading(false);
    };

    return (
        <div className="space-y-6">
            <Card className="bg-slate-900 border-slate-800">
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Trophy className="text-yellow-500" />
                        New Cardio Duel
                    </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">

                    {/* Settings */}
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <label className="text-sm font-medium text-slate-400">Activity</label>
                            <Select value={activityType} onValueChange={setActivityType}>
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="RUNNING">
                                        <div className="flex items-center gap-2"><Footprints className="h-4 w-4" /> Running</div>
                                    </SelectItem>
                                    <SelectItem value="CYCLING">
                                        <div className="flex items-center gap-2"><Bike className="h-4 w-4" /> Cycling</div>
                                    </SelectItem>
                                </SelectContent>
                            </Select>
                        </div>

                        <div className="space-y-2">
                            <label className="text-sm font-medium text-slate-400">Target Distance</label>
                            <Select value={distance} onValueChange={setDistance}>
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="3">3 km</SelectItem>
                                    <SelectItem value="5">5 km</SelectItem>
                                    <SelectItem value="10">10 km</SelectItem>
                                    <SelectItem value="21.1">Half Marathon</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    {/* Opponent Selection */}
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-slate-400">Select Rival (Matched by Power Rating)</label>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-2 max-h-60 overflow-y-auto">
                            {opponents.map((opp) => (
                                <div
                                    key={opp.id}
                                    onClick={() => setSelectedOpponent(opp.id)}
                                    className={`p-3 rounded-lg border cursor-pointer transition-all flex items-center justify-between ${selectedOpponent === opp.id
                                        ? "border-emerald-500 bg-emerald-900/20"
                                        : "border-slate-700 hover:bg-slate-800"
                                        }`}
                                >
                                    <div className="flex items-center gap-3">
                                        <Avatar className="h-8 w-8">
                                            <AvatarFallback>{opp.heroName[0]}</AvatarFallback>
                                        </Avatar>
                                        <div>
                                            <div className="font-semibold text-sm">{opp.heroName}</div>
                                            <div className="text-xs text-slate-500">Lvl {opp.level} • PR: {Math.round(opp.titan?.powerRating || 0)}</div>
                                        </div>
                                    </div>
                                    {selectedOpponent === opp.id && <div className="h-2 w-2 rounded-full bg-emerald-500" />}
                                </div>
                            ))}
                        </div>
                    </div>

                    <Button
                        className="w-full bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-500 hover:to-teal-500"
                        disabled={!selectedOpponent || loading}
                        onClick={handleCreateDuel}
                    >
                        {loading ? "Sending..." : "Send Challenge"}
                    </Button>

                </CardContent>
            </Card>
        </div>
    );
}

