        </Card>

        {/* STANDARD EQUIPMENT GRID */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {ALL_EQUIPMENT.map((eq) => {
            const isSelected = owned.includes(eq.type);
            const isHyperPro = eq.type === EquipmentType.HYPER_PRO;

            return (
              <div
                key={eq.type}
                onClick={() => toggleEquipment(eq.type)}
                className={`
                                    relative p-4 rounded-lg border-2 cursor-pointer transition-all duration-200
                                    flex items-center justify-between group
                                    ${isSelected
                    ? isHyperPro
                      ? "bg-rarity-epic/10 border-rarity-epic"
                      : "bg-forge-800 border-rarity-common"
                    : "bg-forge-900/30 border-forge-border hover:border-gray-500"
                  }
                                `}
              >
                <span
                  className={`font-heading tracking-wider ${isSelected ? "text-white" : "text-gray-500"}`}
                >
                  {eq.label}
                </span>
                <div
                  className={`w-4 h-4 rounded-sm border ${isSelected ? (isHyperPro ? "bg-rarity-epic border-rarity-epic" : "bg-rarity-common border-rarity-common") : "border-gray-600"}`}
                ></div>
              </div>
            );
          })}
        </div>

        {/* BATTLE GEAR (RPG INVENTORY) */}
        <BattleGearSection />

        <div className="flex justify-center mt-12">
          <p className="text-xs font-mono text-forge-muted opacity-50">
            ID: {StorageService.db ? "DB_CONNECTED" : "DB_OFFLINE"}{" "}
            {/* v1.2.0 */}
          </p>
        </div>
      </div>
    </div>
  );
};

export default EquipmentArmory;

import React, { useState, useEffect } from "react";
import { Equipment, EquipmentCategory } from "@/types";
import { StorageService } from "@/services/storage";
import {
  X,
  Dumbbell,
  Shield,
  Plus,
  Trash2,
  Box,
  PackagePlus,
  Hammer,
  Bike,
  Check,
} from "lucide-react";
import { playSound } from "@/utils";

interface EquipmentArmoryProps {
  onClose: () => void;
}

const PRESETS: Partial<Equipment>[] = [
  { name: "Power Rack", category: "Rack" },
  { name: "Olympic Barbell", category: "Barbell" },
  { name: "Bumper Plates", category: "Weights" },
  { name: "Iron Plates", category: "Weights" },
  { name: "Adjustable Bench", category: "Accessory" },
  { name: "Dumbbells (Adjustable)", category: "Weights" },
  { name: "Kettlebells", category: "Weights" },
  { name: "Air Bike", category: "Cardio" },
  { name: "Rower", category: "Cardio" },
  { name: "Treadmill", category: "Cardio" },
  { name: "Cable Pulley", category: "Machine" },
  { name: "Leg Extension/Curl", category: "Machine" },
  { name: "GHD", category: "Accessory" },
];

const EquipmentArmory: React.FC<EquipmentArmoryProps> = ({ onClose }) => {
  const [inventory, setInventory] = useState<Equipment[]>([]);
  const [activeTab, setActiveTab] = useState<"INVENTORY" | "REQUISITION">(
    "INVENTORY",
  );

  // Custom Add State
  const [customName, setCustomName] = useState("");
  const [customCategory, setCustomCategory] =
    useState<EquipmentCategory>("Accessory");

  useEffect(() => {
    const load = async () => {
      const data = await StorageService.getState<Equipment[]>("equipment");
      if (data) setInventory(data);
    };
    load();
  }, []);

  const saveInventory = async (newInventory: Equipment[]) => {
    setInventory(newInventory);
    await StorageService.saveState("equipment", newInventory);
  };

  const addEquipment = (item: Partial<Equipment>) => {
    const newEq: Equipment = {
      id: `eq_${Date.now()}_${Math.random()}`,
      name: item.name || "Unknown Item",
      category: item.category || "Accessory",
      isOwned: true,
    };
    const updated = [...inventory, newEq];
    saveInventory(updated);
    playSound("ding");
  };

  const removeEquipment = (id: string) => {
    playSound("ui_click");
    const updated = inventory.filter((i) => i.id !== id);
    saveInventory(updated);
  };

  const handleCustomAdd = () => {
    if (!customName) {
      playSound("ui_error");
      return;
    }
    addEquipment({ name: customName, category: customCategory });
    setCustomName("");
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-sm p-4 animate-fade-in font-serif">
      <div className="w-full max-w-4xl bg-armor border-2 border-steel rounded-lg shadow-[0_0_50px_rgba(0,0,0,0.8)] flex flex-col max-h-[90vh] overflow-hidden">
        {/* Header */}
        <div className="p-6 bg-zinc-900 border-b border-zinc-800 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="p-3 bg-zinc-800 border border-zinc-600 rounded">
              <Box className="w-6 h-6 text-zinc-300" />
            </div>
            <div>
              <h2 className="text-2xl font-black uppercase text-zinc-200 tracking-tighter">
                The Armory
              </h2>
              <p className="text-xs text-zinc-500 font-sans tracking-widest">
                Home Gym Logistics & Supply
              </p>
            </div>
          </div>
          <button
            onClick={onClose}
            aria-label="Close"
            className="text-zinc-500 hover:text-white transition-colors"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-steel bg-void">
          <button
            onClick={() => {
              playSound("ui_click");
              setActiveTab("INVENTORY");
            }}
            onMouseEnter={() => playSound("ui_hover")}
            className={`flex-1 py-4 text-xs font-bold uppercase tracking-widest transition-colors ${activeTab === "INVENTORY" ? "bg-armor text-clay border-t-2 border-clay" : "text-zinc-600 hover:text-zinc-400"}`}
          >
            Current Inventory ({inventory.length})
          </button>
          <button
            onClick={() => {
              playSound("ui_click");
              setActiveTab("REQUISITION");
            }}
            onMouseEnter={() => playSound("ui_hover")}
            className={`flex-1 py-4 text-xs font-bold uppercase tracking-widest transition-colors ${activeTab === "REQUISITION" ? "bg-armor text-clay border-t-2 border-clay" : "text-zinc-600 hover:text-zinc-400"}`}
          >
            Requisition (Add New)
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')]">
          {/* INVENTORY TAB */}
          {activeTab === "INVENTORY" && (
            <div className="space-y-4">
              {inventory.length === 0 ? (
                <div className="text-center py-20 opacity-50">
                  <Box className="w-16 h-16 mx-auto text-zinc-700 mb-4" />
                  <h3 className="text-zinc-500 font-bold uppercase">
                    Armory Empty
                  </h3>
                  <p className="text-zinc-600 text-sm mt-2">
                    Go to Requisition to stock your gym.
                  </p>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {inventory.map((item) => (
                    <div
                      key={item.id}
                      className="bg-armor border border-steel p-4 rounded group hover:border-clay transition-colors relative"
                    >
                      <div className="flex justify-between items-start">
                        <div className="flex items-center gap-3">
                          <div className="p-2 bg-zinc-900 rounded text-zinc-500">
                            {item.category === "Barbell" && (
                              <Hammer className="w-5 h-5" />
                            )}
                            {item.category === "Weights" && (
                              <Dumbbell className="w-5 h-5" />
                            )}
                            {item.category === "Cardio" && (
                              <Bike className="w-5 h-5" />
                            )}
                            {item.category === "Rack" && (
                              <Shield className="w-5 h-5" />
                            )}
                            {(item.category === "Accessory" ||
                              item.category === "Machine") && (
                                <Box className="w-5 h-5" />
                              )}
                          </div>
                          <div>
                            <div className="font-bold text-zinc-200">
                              {item.name}
                            </div>
                            <div className="text-[10px] uppercase text-zinc-600 font-bold tracking-wider">
                              {item.category}
                            </div>
                          </div>
                        </div>
                        <button
                          onClick={() => removeEquipment(item.id)}
                          className="opacity-0 group-hover:opacity-100 text-zinc-600 hover:text-red-500 transition-all"
                          title="Scrap Item"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* REQUISITION TAB */}
          {activeTab === "REQUISITION" && (
            <div className="space-y-8">
              {/* Standard Issue */}
              <div>
                <h3 className="text-sm font-bold text-zinc-500 uppercase tracking-widest mb-4 flex items-center gap-2 border-b border-zinc-800 pb-2">
                  <PackagePlus className="w-4 h-4" /> Standard Issue Gear
                </h3>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                  {PRESETS.map((preset, idx) => {
                    const isOwned = inventory.some(
                      (i) => i.name === preset.name,
                    );
                    return (
                      <button
                        key={idx}
                        onClick={() => !isOwned && addEquipment(preset)}
                        onMouseEnter={() => !isOwned && playSound("ui_hover")}
                        disabled={isOwned}
                        className={`p-3 rounded border text-left flex items-center justify-between transition-all ${isOwned
                          ? "bg-void border-steel opacity-50 cursor-default"
                          : "bg-armor border-steel/50 hover:border-clay hover:bg-armor/80"
                          }`}
                      >
                        <span
                          className={`text-sm font-bold ${isOwned ? "text-zinc-600" : "text-zinc-300"}`}
                        >
                          {preset.name}
                        </span>
                        {isOwned ? (
                          <Check className="w-4 h-4 text-green-800" />
                        ) : (
                          <Plus className="w-4 h-4 text-zinc-500" />
                        )}
                      </button>
                    );
                  })}
                </div>
              </div>

              {/* Custom Order */}
              <div className="bg-armor border border-steel p-6 rounded-lg">
                <h3 className="text-sm font-bold text-zinc-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                  <Hammer className="w-4 h-4" /> Custom Fabrication
                </h3>
                <div className="flex flex-col md:flex-row gap-4 items-end">
                  <div className="flex-1 space-y-1 w-full">
                    <label className="text-[10px] uppercase font-bold text-zinc-600">
                      Item Name
                    </label>
                    <input
                      value={customName}
                      onChange={(e) => setCustomName(e.target.value)}
                      placeholder="e.g. Reverse Hyper"
                      className="w-full bg-void border border-steel p-3 rounded text-zinc-200 focus:border-clay focus:outline-none"
                    />
                  </div>
                  <div className="w-full md:w-48 space-y-1">
                    <label className="text-[10px] uppercase font-bold text-zinc-600">
                      Category
                    </label>
                    <select
                      value={customCategory}
                      onChange={(e) =>
                        setCustomCategory(e.target.value as EquipmentCategory)
                      }
                      aria-label="Category"
                      className="w-full bg-void border border-steel p-3 rounded text-zinc-200 focus:border-clay focus:outline-none"
                    >
                      <option value="Barbell">Barbell</option>
                      <option value="Weights">Weights</option>
                      <option value="Machine">Machine</option>
                      <option value="Cardio">Cardio</option>
                      <option value="Rack">Rack</option>
                      <option value="Accessory">Accessory</option>
                    </select>
                  </div>
                  <button
                    onClick={handleCustomAdd}
                    disabled={!customName}
                    className="w-full md:w-auto px-6 py-3 bg-clay hover:bg-clay/80 text-black font-bold uppercase tracking-widest rounded disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    Fabricate
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default EquipmentArmory;

import React, { useState, useMemo } from "react";
import { Search, Plus, Dumbbell, ChevronRight } from "lucide-react";

interface ExerciseLibraryProps {
  onSelect: (exerciseId: string) => void;
  onClose: () => void;
}

// Mock Database - In real app, this comes from Prisma/API
const EXERCISE_DB = [
  {
    id: "ex_bench_press",
    name: "Bench Press",
    muscle: "Chest",
    equipment: "Barbell",
  },
  {
    id: "ex_squat",
    name: "Barbell Squat",
    muscle: "Legs",
    equipment: "Barbell",
  },
  { id: "ex_deadlift", name: "Deadlift", muscle: "Back", equipment: "Barbell" },
  {
    id: "ex_ohp",
    name: "Overhead Press",
    muscle: "Shoulders",
    equipment: "Barbell",
  },
  { id: "ex_pullup", name: "Pull Up", muscle: "Back", equipment: "Bodyweight" },
  { id: "ex_dip", name: "Dips", muscle: "Chest", equipment: "Bodyweight" },
  {
    id: "ex_db_curl",
    name: "Dumbbell Curl",
    muscle: "Biceps",
    equipment: "Dumbbell",
  },
  {
    id: "ex_tricep_ext",
    name: "Tricep Extension",
    muscle: "Triceps",
    equipment: "Cable",
  },
];

const MUSCLE_GROUPS = [
  "All",
  "Chest",
  "Back",
  "Legs",
  "Shoulders",
  "Arms",
  "Core",
];

import { createCustomExercise, getCustomExercises } from "@/features/strength/actions/custom-exercises";

const ExerciseLibrary: React.FC<ExerciseLibraryProps> = ({
  onSelect,
  onClose,
}) => {
  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState("All");
  const [isCreating, setIsCreating] = useState(false);
  const [customExercises, setCustomExercises] = useState<any[]>([]);

  // Form State
  const [newExName, setNewExName] = useState("");
  const [newExMuscle, setNewExMuscle] = useState("Chest");
  const [newExEquip, setNewExEquip] = useState("Barbell");
  const [isSubmitting, setIsSubmitting] = useState(false);

  React.useEffect(() => {
    // Load custom exercises
    getCustomExercises().then(data => setCustomExercises(data));
  }, []);

  const handleCreate = async () => {
    setIsSubmitting(true);
    const newEx = await createCustomExercise({
      name: newExName,
      muscle: newExMuscle,
      equipment: newExEquip
    });
    setCustomExercises(prev => [...prev, newEx]);
    setIsCreating(false);
    setIsSubmitting(false);
    // Reset form
    setNewExName("");
  };

  const allExercises = useMemo(() => {
    return [...customExercises, ...EXERCISE_DB];
  }, [customExercises]);

  const filteredExercises = useMemo(() => {
    return allExercises.filter((ex) => {
      const matchesSearch = ex.name
        .toLowerCase()
        .includes(search.toLowerCase());
      const matchesFilter = filter === "All" || ex.muscle === filter || (ex.muscleGroup === filter); // Handle schema variance
      return matchesSearch && matchesFilter;
    });
  }, [search, filter, allExercises]);

  return (
    <div className="fixed inset-0 z-[100] bg-zinc-950 flex flex-col animate-in slide-in-from-bottom-10">
      {/* Header */}
      <div className="p-4 border-b border-zinc-800 bg-zinc-900 flex items-center justify-between">
        <h2 className="text-lg font-bold text-white flex items-center gap-2">
          <Dumbbell className="w-5 h-5 text-indigo-400" />
          Exercise Library
        </h2>
        <button
          onClick={onClose}
          className="text-zinc-400 hover:text-white text-sm font-medium"
        >
          Close
        </button>
      </div>

      {/* Search & Filter */}
      <div className="p-4 space-y-4 bg-zinc-900/50">
        <div className="relative">
          <Search className="absolute left-3 top-3 w-5 h-5 text-zinc-500" />
          <input
            type="text"
            placeholder="Search exercises..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full bg-zinc-950 border border-zinc-800 rounded-lg py-3 pl-10 pr-4 text-white focus:outline-none focus:border-indigo-500 transition-colors"
            autoFocus
          />
        </div>
        <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
          {MUSCLE_GROUPS.map((group) => (
            <button
              key={group}
              onClick={() => setFilter(group)}
              className={`px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-colors
                                ${filter === group
                  ? "bg-indigo-600 text-white"
                  : "bg-zinc-800 text-zinc-400 hover:bg-zinc-700"
                }
                            `}
            >
              {group}
            </button>
          ))}
        </div>
      </div>

      {/* Creation Mode or List */}
      {isCreating ? (
        <div className="p-4 space-y-4 bg-zinc-900/10 m-4 border border-zinc-800 rounded-xl animate-fade-in">
          <h3 className="font-bold text-white">Create Custom Exercise</h3>

          <div className="space-y-1">
            <label className="text-xs text-zinc-500">Name</label>
            <input
              value={newExName}
              onChange={e => setNewExName(e.target.value)}
              className="w-full bg-black border border-zinc-800 rounded p-2 text-white"
              placeholder="e.g. Plate Pinch"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-xs text-zinc-500">Muscle</label>
              <select
                value={newExMuscle}
                onChange={e => setNewExMuscle(e.target.value)}
                className="w-full bg-black border border-zinc-800 rounded p-2 text-white"
              >
                {MUSCLE_GROUPS.filter(g => g !== "All").map(g => <option key={g} value={g}>{g}</option>)}
              </select>
            </div>
            <div className="space-y-1">
              <label className="text-xs text-zinc-500">Equipment</label>
              <select
                value={newExEquip}
                onChange={e => setNewExEquip(e.target.value)}
                className="w-full bg-black border border-zinc-800 rounded p-2 text-white"
              >
                <option value="Barbell">Barbell</option>
                <option value="Dumbbell">Dumbbell</option>
                <option value="Machine">Machine</option>
                <option value="Bodyweight">Bodyweight</option>
                <option value="Cable">Cable</option>
              </select>
            </div>
          </div>

          <div className="flex gap-2 pt-2">
            <button onClick={() => setIsCreating(false)} className="flex-1 bg-zinc-800 text-white rounded p-2 text-sm font-bold">Cancel</button>
            <button onClick={handleCreate} disabled={!newExName || isSubmitting} className="flex-1 bg-magma text-white rounded p-2 text-sm font-bold disabled:opacity-50">
              {isSubmitting ? "Saving..." : "Create Exercise"}
            </button>
          </div>
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto p-4 space-y-2">
          {filteredExercises.map((ex) => (
            <button
              key={ex.id}
              onClick={() => onSelect(ex.id)}
              className="w-full text-left p-4 bg-zinc-900/30 border border-zinc-800 rounded-xl hover:bg-zinc-800/50 hover:border-indigo-500/30 transition-all group flex items-center justify-between"
            >
              <div>
                <div className="font-bold text-zinc-200">{ex.name}</div>
                <div className="text-xs text-zinc-500 mt-1 flex gap-2">
                  <span className="bg-zinc-800 px-1.5 py-0.5 rounded">
                    {ex.muscle || ex.muscleGroup}
                  </span>
                  <span className="bg-zinc-800 px-1.5 py-0.5 rounded">
                    {ex.equipment}
                  </span>
                  {ex.isCustom && <span className="bg-indigo-900/50 text-indigo-400 px-1.5 py-0.5 rounded">Custom</span>}
                </div>
              </div>
              <ChevronRight className="w-5 h-5 text-zinc-600 group-hover:text-indigo-400" />
            </button>
          ))}

          {filteredExercises.length === 0 && (
            <div className="text-center py-12 text-zinc-500">
              <p>No exercises found.</p>
              <button className="mt-4 text-indigo-400 text-sm font-bold flex items-center justify-center gap-2 mx-auto hover:text-indigo-300">
                <Plus className="w-4 h-4" /> Create Custom Exercise
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

