import React, { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { playSound } from "../../../utils";

interface BerserkerModeProps {
  lastExerciseName: string;
  onComplete: (reps: number) => void;
}

const BERSERKER_DURATION = 15; // 15 seconds for intense AMRAP

const BerserkerMode: React.FC<BerserkerModeProps> = ({
  lastExerciseName,
  onComplete,
}) => {
  const [reps, setReps] = useState<string>("");
  const [timeLeft, setTimeLeft] = useState(BERSERKER_DURATION);

  useEffect(() => {
    playSound("loot_epic");
    const timer = setInterval(() => {
      setTimeLeft((prevTime) => {
        if (prevTime <= 1) {
          clearInterval(timer);
          return 0;
        }
        return prevTime - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  const handleComplete = () => {
    const finalReps = parseInt(reps, 10) || 0;
    playSound("achievement");
    onComplete(finalReps);
  };

  const isTimerActive = timeLeft > 0;
  const progressPercentage = (timeLeft / BERSERKER_DURATION) * 100;

  return (
    <motion.div
      className="fixed inset-0 bg-black bg-opacity-90 flex items-center justify-center z-50 p-4"
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
    >
      <Card variant="glass" className="w-full max-w-md text-center border-blood shadow-glow-blood">
        <h2 className="font-heading text-4xl text-blood animate-pulse tracking-widest">
          BERSERKER MODE
        </h2>
        <p className="font-mono text-rune mt-2">
          Final set of {lastExerciseName}.
        </p>
        <p className="text-white text-lg mt-1">As Many Reps As Possible!</p>

        <div className="my-8">
          <div className="relative w-48 h-48 mx-auto flex items-center justify-center">
            <svg
              className="absolute inset-0 w-full h-full"
              viewBox="0 0 100 100"
            >
              <circle
                className="text-gray-800"
                strokeWidth="5"
                stroke="currentColor"
                fill="transparent"
                r="45"
                cx="50"
                cy="50"
              />
              <motion.circle
                className="text-blood"
                strokeWidth="5"
                strokeDasharray={2 * Math.PI * 45}
                strokeDashoffset={
                  2 * Math.PI * 45 * (1 - progressPercentage / 100)
                }
                strokeLinecap="round"
                fill="transparent"
                r="45"
                cx="50"
                cy="50"
                transform="rotate(-90 50 50)"
                initial={{ strokeDashoffset: 2 * Math.PI * 45 }}
                animate={{
                  strokeDashoffset:
                    2 * Math.PI * 45 * (1 - progressPercentage / 100),
                }}
                transition={{ duration: 1, ease: "linear" }}
              />
            </svg>
            <span className="font-mono text-5xl text-whitetabular-nums">
              {isTimerActive ? timeLeft : "0"}
            </span>
          </div>
          <p className="font-mono text-sm text-rune mt-2">TIME REMAINING</p>
        </div>

        {isTimerActive ? (
          <div className="h-20">
            <p className="text-forge-muted animate-pulse">Finish your set...</p>
          </div>
        ) : (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="flex flex-col items-center"
          >
            <input
              type="number"
              value={reps}
              onChange={(e) => setReps(e.target.value)}
              placeholder="Enter Your Reps"
              className="w-48 text-center bg-black border-2 border-gray-600 rounded-md p-2 text-2xl mb-4 focus:border-blood focus:outline-none"
              autoFocus
            />
            <Button
              onClick={handleComplete}
              variant="magma"
              className="px-10"
            >
              Log Fury
            </Button>
          </motion.div>
        )}
      </Card>
    </motion.div>
  );
};

export default BerserkerMode;

import prisma from "@/lib/prisma";
import { getISOWeek, getISOWeekYear, format } from "date-fns";

export const CONTEST_COST_GOLD = 1000;
export const CONTEST_DURATION_DAYS = 7;

export class TerritoryService {
    /**
     * Fetch all territories with their current owners and active contests.
     */
    static async getTerritories() {
        return await prisma.territory.findMany({
            include: {
                controlledBy: {
                    select: {
                        id: true,
                        name: true,
                        tag: true,
                    },
                },
                activeContests: {
                    where: { status: "active" },
                    include: {
                        attacker: {
                            select: {
                                id: true,
                                name: true,
                                tag: true,
                            },
                        },
                    },
                },
            },
        });
    }

    /**
     * Claim an unclaimed territory.
     * Requires the user to be a guild leader/officer (checked in action).
     */
    static async claimTerritory(guildId: string, territoryId: string, userId: string) {
        return await prisma.$transaction(async (tx) => {
            const territory = await tx.territory.findUnique({
                where: { id: territoryId },
            });

            if (!territory) throw new Error("Territory not found");
            if (territory.controlledById) throw new Error("Territory already claimed");

            // Check if guild has enough gold (proxied by user gold for now or add guild gold)
            const user = await tx.user.findUnique({ where: { id: userId } });
            if (!user || user.gold < CONTEST_COST_GOLD) {
                throw new Error(`Insufficient gold. Need ${CONTEST_COST_GOLD}.`);
            }

            await tx.user.update({
                where: { id: userId },
                data: { gold: { decrement: CONTEST_COST_GOLD } },
            });

            return await tx.territory.update({
                where: { id: territoryId },
                data: {
                    controlledById: guildId,
                    controlledAt: new Date(),
                },
            });
        });
    }

    /**
     * Initiate a contest against an owned territory.
     */
    static async contestTerritory(attackerId: string, territoryId: string, userId: string) {
        return await prisma.$transaction(async (tx) => {
            const territory = await tx.territory.findUnique({
                where: { id: territoryId },
            });

            if (!territory) throw new Error("Territory not found");
            if (!territory.controlledById) throw new Error("Territory must be claimed before contesting");
            if (territory.controlledById === attackerId) throw new Error("Cannot contest your own territory");

            // Check for active contest
            const activeContest = await tx.territoryContest.findFirst({
                where: { territoryId, status: "active" },
            });
            if (activeContest) throw new Error("Territory is already under contest");

            // Check gold
            const user = await tx.user.findUnique({ where: { id: userId } });
            if (!user || user.gold < CONTEST_COST_GOLD) {
                throw new Error(`Insufficient gold. Need ${CONTEST_COST_GOLD}.`);
            }

            await tx.user.update({
                where: { id: userId },
                data: { gold: { decrement: CONTEST_COST_GOLD } },
            });

            const now = new Date();
            const endsAt = new Date(now.getTime() + CONTEST_DURATION_DAYS * 24 * 60 * 60 * 1000);

            return await tx.territoryContest.create({
                data: {
                    territoryId,
                    attackerId,
                    defenderId: territory.controlledById,
                    startsAt: now,
                    endsAt,
                    status: "active",
                },
            });
        });
    }

    /**
     * Update contest scores for ALL active contests a guild is involved in.
     */
    static async recordGuildActivity(guildId: string, volume: number) {
        const contests = await prisma.territoryContest.findMany({
            where: {
                OR: [{ attackerId: guildId }, { defenderId: guildId }],
                status: "active",
            },
        });

        for (const contest of contests) {
            if (contest.attackerId === guildId) {
                await prisma.territoryContest.update({
                    where: { id: contest.id },
                    data: { attackerScore: { increment: Math.floor(volume) } },
                });
            } else if (contest.defenderId === guildId) {
                await prisma.territoryContest.update({
                    where: { id: contest.id },
                    data: { defenderScore: { increment: Math.floor(volume) } },
                });
            }
        }
    }

    static async conquestFromActivity(guildId: string, volume: number) {
        return await this.recordGuildActivity(guildId, volume);
    }

    static async getUserTerritoryStats(userId: string) {
        const user = await prisma.user.findUnique({
            where: { id: userId },
            select: { guildId: true }
        });

        if (!user?.guildId) return null;

        const allTerritories = await prisma.territory.findMany({
            where: { controlledById: user.guildId }
        });

        // Cap at 3 for bonuses
        const cappedTerritories = allTerritories.slice(0, 3);

        // Map to TerritoryStatsData expected by the UI
        return {
            ownedTiles: allTerritories.length,
            contestedTiles: 0, // Placeholder
            totalControlPoints: allTerritories.length * 10,
            dailyGold: cappedTerritories.length * 100,
            dailyXP: cappedTerritories.length * 50,
            largestConnectedArea: allTerritories.length // Placeholder
        };
    }

    static async distributeDailyIncome() {
        const guildsWithTerritories = await prisma.guild.findMany({
            where: {
                territories: {
                    some: {}
                }
            },
            include: {
                territories: {
                    select: { id: true }
                }
            }
        });

        for (const guild of guildsWithTerritories) {
            const count = Math.min(guild.territories.length, 3);
            if (count === 0) continue;

            const totalGold = count * 100;
            const totalXP = count * 50;

            await prisma.guild.update({
                where: { id: guild.id },
                data: {
                    gold: { increment: totalGold },
                    xp: { increment: totalXP }
                }
            });
        }
    }

    static async runWeeklySettlement() {
        return await this.resolveExpiredContests();
    }

    /**
     * Returns the current state of all territories for map rendering.
     */
    static async getMapData(): Promise<any[]> {
        const now = new Date();
        const weekNumber = getISOWeek(now);
        const year = getISOWeekYear(now);

        const territories = await prisma.territory.findMany({
            include: {
                controlledBy: {
                    select: { id: true, name: true, tag: true },
                },
                activeContests: {
                    where: { status: "active" },
                    include: {
                        attacker: { select: { id: true, name: true, tag: true } },
                        defender: { select: { id: true, name: true, tag: true } },
                    },
                },
            },
        });

        return territories;
    }

    /**
     * Resolve expired contests (Weekly Reset).
       */
    static async resolveExpiredContests() {
        const now = new Date();
        const expired = await prisma.territoryContest.findMany({
            where: { status: "active", endsAt: { lte: now } },
        });

        for (const contest of expired) {
            const winnerId = contest.attackerScore > contest.defenderScore
                ? contest.attackerId
                : contest.defenderId;

            await prisma.$transaction(async (tx) => {
                await tx.territoryContest.update({
                    where: { id: contest.id },
                    data: { status: "resolved", winnerId },
                });

                if (winnerId && winnerId !== contest.defenderId) {
                    await tx.territory.update({
                        where: { id: contest.territoryId },
                        data: {
                            controlledById: winnerId,
                            controlledAt: now,
                        },
                    });

                    // Log history
                    await tx.territoryHistory.create({
                        data: {
                            territoryId: contest.territoryId,
                            guildId: winnerId,
                            claimedAt: now,
                            weekNumber: getISOWeek(now),
                            year: getISOWeekYear(now),
                        },
                    });
                }
            });
        }
    }
}

import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { PowerRatingService } from "../PowerRatingService";
import prisma from "@/lib/prisma";
import { subDays, subWeeks, startOfWeek } from "date-fns";

vi.mock("@/lib/prisma", () => ({
    default: {
        exerciseLog: { findMany: vi.fn() },
        cardioLog: { findMany: vi.fn() },
    },
}));

describe("PowerRatingService", () => {
    beforeEach(() => {
        vi.clearAllMocks();
        vi.useFakeTimers();
    });

    afterEach(() => {
        vi.useRealTimers();
    });

    describe("getConsecutiveWeeks", () => {
        it("should return 0 if no logs exist", async () => {
            vi.setSystemTime(new Date("2024-03-20T12:00:00Z")); // Wednesday
            vi.mocked(prisma.exerciseLog.findMany).mockResolvedValue([]);
            vi.mocked(prisma.cardioLog.findMany).mockResolvedValue([]);

            const weeks = await PowerRatingService.getConsecutiveWeeks("user-1");
            expect(weeks).toBe(0);
        });

        it("should count consecutive weeks from logs", async () => {
            const now = new Date("2024-03-20T12:00:00Z");
            vi.setSystemTime(now);

            const lastWeek = subWeeks(now, 1);
            const twoWeeksAgo = subWeeks(now, 2);

            vi.mocked(prisma.exerciseLog.findMany).mockResolvedValue([
                { date: now },
                { date: lastWeek },
                { date: twoWeeksAgo }
            ] as any);
            vi.mocked(prisma.cardioLog.findMany).mockResolvedValue([]);

            const weeks = await PowerRatingService.getConsecutiveWeeks("user-1");
            expect(weeks).toBe(3);
        });

        it("should handle current week gap (still counting previous consecutive weeks)", async () => {
            const now = new Date("2024-03-20T12:00:00Z");
            vi.setSystemTime(now);

            const lastWeek = subWeeks(now, 1);
            const twoWeeksAgo = subWeeks(now, 2);

            vi.mocked(prisma.exerciseLog.findMany).mockResolvedValue([
                { date: lastWeek },
                { date: twoWeeksAgo }
            ] as any);
            vi.mocked(prisma.cardioLog.findMany).mockResolvedValue([]);

            const weeks = await PowerRatingService.getConsecutiveWeeks("user-1");
            expect(weeks).toBe(2);
        });

        it("should break streak on missing mid-week", async () => {
            const now = new Date("2024-03-20T12:00:00Z");
            vi.setSystemTime(now);
            const threeWeeksAgo = subWeeks(now, 3);

            vi.mocked(prisma.exerciseLog.findMany).mockResolvedValue([
                { date: now },
                { date: threeWeeksAgo }
            ] as any);
            vi.mocked(prisma.cardioLog.findMany).mockResolvedValue([]);

            const weeks = await PowerRatingService.getConsecutiveWeeks("user-1");
            expect(weeks).toBe(1); // Only current week
        });

        it("should correctly handle year boundaries", async () => {
            // Monday Jan 1st 2024 is Week 1 of 2024
            // Last week of 2023 is Week 52
            const jan1 = new Date("2024-01-01T12:00:00Z");
            vi.setSystemTime(jan1);

            const decLastWeek = subWeeks(jan1, 1); // Late Dec 2023

            vi.mocked(prisma.exerciseLog.findMany).mockResolvedValue([
                { date: jan1 },
                { date: decLastWeek }
            ] as any);
            vi.mocked(prisma.cardioLog.findMany).mockResolvedValue([]);

            const weeks = await PowerRatingService.getConsecutiveWeeks("user-1");
            expect(weeks).toBe(2);
        });
    });
});

